{
  "name": "PharmaGuard ADR Monitor",
  "description": "A pharmacovigilance tool to monitor adverse drug reactions against package insert baselines using Gemini AI for extraction.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface AdverseReaction {
  id: string;
  name: string;
  baselineRate: number; // Stored as decimal (e.g., 0.01 for 1%)
  frequencyText?: string; // e.g., "Common", "Rare", "1/100"
}

export interface QuarterlyData {
  id: string;
  quarterLabel: string; // e.g., "2024 Q1"
  salesVolume: number; // The denominator
  reactionCounts: Record<string, number>; // key is AdverseReaction.id, value is count
}

export interface Drug {
  id: string;
  name: string;
  description?: string;
  reactions: AdverseReaction[];
  history: QuarterlyData[];
}

export type ViewState = 'dashboard' | 'add-drug' | 'entry' | 'analysis';

import { GoogleGenAI, Type } from "@google/genai";
import { AdverseReaction } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Helper to convert file to Base64
export const fileToGenerativePart = async (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      // Remove data url prefix (e.g., "data:image/jpeg;base64,")
      const base64Data = base64String.split(',')[1];
      resolve(base64Data);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

export const extractReactionsFromInput = async (
  textInput: string, 
  imageFile?: File
): Promise<Omit<AdverseReaction, 'id'>[]> => {

  const parts: any[] = [];

  if (imageFile) {
    const base64Data = await fileToGenerativePart(imageFile);
    parts.push({
      inlineData: {
        mimeType: imageFile.type,
        data: base64Data
      }
    });
  }

  if (textInput) {
    parts.push({ text: textInput });
  }

  const prompt = `
    You are a pharmacological expert. Analyze the provided drug package insert (text or image).
    Identify all listed Adverse Drug Reactions (ADRs) or side effects.

    For each reaction:
    1. Extract the name (e.g., "Headache", "Nausea").
    2. Extract the frequency as described (e.g., "Common", "1%", "1/100").
    3. Convert the frequency to a strict decimal number (baselineRate). 
       - If "1%", baselineRate is 0.01. 
       - If "1/1000", baselineRate is 0.001.
       - If qualitative terms are used, estimate based on MedDRA: Very Common (>=0.1), Common (>=0.01 and <0.1), Uncommon (>=0.001 and <0.01), Rare (>=0.0001 and <0.001). Use the lower bound for safety comparisons.
       - If no frequency is listed, default to 0.0001 (Unknown/Rare).

    Return a valid JSON array.
  `;

  // Schema definition
  const responseSchema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        name: { type: Type.STRING },
        frequencyText: { type: Type.STRING },
        baselineRate: { type: Type.NUMBER },
      },
      required: ["name", "baselineRate"],
    },
  };

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        role: 'user',
        parts: [
            ...parts,
            { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const jsonText = response.text;
    if (!jsonText) return [];

    return JSON.parse(jsonText);
  } catch (error) {
    console.error("Gemini Extraction Error:", error);
    throw new Error("Failed to extract data using AI.");
  }
};

