import React, { useState } from 'react';
import { Upload, FileText, Loader2, Save, X, Sparkles } from 'lucide-react';
import { Drug, AdverseReaction } from '../types';
import { extractReactionsFromInput } from '../services/geminiService';
import { v4 as uuidv4 } from 'uuid';

interface DrugFormProps {
  onSave: (drug: Drug) => void;
  onCancel: () => void;
}

const DrugForm: React.FC<DrugFormProps> = ({ onSave, onCancel }) => {
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [textInput, setTextInput] = useState('');
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [isExtracting, setIsExtracting] = useState(false);
  const [reactions, setReactions] = useState<Omit<AdverseReaction, 'id'>[]>([]);

  const handleExtraction = async () => {
    if (!textInput && !imageFile) {
      alert("Please provide text or an image of the package insert.");
      return;
    }
    setIsExtracting(true);
    try {
      const extracted = await extractReactionsFromInput(textInput, imageFile || undefined);
      setReactions(extracted);
    } catch (e) {
      alert("Failed to extract data. Please check your API key or try again.");
    } finally {
      setIsExtracting(false);
    }
  };

  const handleSave = () => {
    if (!name) return alert("Drug name is required");
    if (reactions.length === 0) return alert("At least one adverse reaction is required");

    const newDrug: Drug = {
      id: uuidv4(),
      name,
      description,
      reactions: reactions.map(r => ({ ...r, id: uuidv4() })),
      history: []
    };
    onSave(newDrug);
  };

  const removeReaction = (idx: number) => {
    setReactions(reactions.filter((_, i) => i !== idx));
  };

  const updateReaction = (idx: number, field: keyof Omit<AdverseReaction, 'id'>, value: any) => {
    const updated = [...reactions];
    updated[idx] = { ...updated[idx], [field]: value };
    setReactions(updated);
  };

  const addEmptyReaction = () => {
    setReactions([...reactions, { name: '', baselineRate: 0.001, frequencyText: 'Manual' }]);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="p-6 border-b border-slate-100 flex justify-between items-center">
        <h3 className="text-lg font-bold text-slate-800">Add New Drug Profile</h3>
        <button onClick={onCancel} className="text-slate-400 hover:text-slate-600"><X size={20} /></button>
      </div>

      <div className="p-6 grid gap-8 lg:grid-cols-2">
        {/* Left Col: Basic Info & Source */}
        <div className="space-y-6">
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Drug Name</label>
            <input 
              type="text" 
              className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all"
              placeholder="e.g., Aspirin Complex"
              value={name}
              onChange={e => setName(e.target.value)}
            />
          </div>
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Description</label>
            <textarea 
              className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none h-24"
              placeholder="Optional notes about the drug..."
              value={description}
              onChange={e => setDescription(e.target.value)}
            />
          </div>

          <div className="bg-slate-50 p-6 rounded-xl border border-dashed border-slate-300">
            <h4 className="font-semibold text-slate-700 flex items-center gap-2 mb-4">
              <Sparkles className="text-purple-500" size={18} />
              AI Auto-Extraction
            </h4>
            <p className="text-sm text-slate-500 mb-4">
              Paste the package insert text (Safety/Adverse Reactions section) or upload an image of the frequency table.
            </p>

            <textarea 
              className="w-full px-4 py-2 border border-slate-300 rounded-lg mb-4 text-sm h-32"
              placeholder="Paste package insert text here..."
              value={textInput}
              onChange={e => setTextInput(e.target.value)}
            />

            <div className="flex items-center gap-4 mb-4">
               <label className="flex-1 cursor-pointer bg-white border border-slate-300 text-slate-600 px-4 py-2 rounded-lg hover:bg-slate-50 flex items-center justify-center gap-2 transition-colors">
                 <Upload size={16} />
                 {imageFile ? imageFile.name : 'Upload Image'}
                 <input type="file" className="hidden" accept="image/*" onChange={e => setImageFile(e.target.files?.[0] || null)} />
               </label>
            </div>

            <button 
              onClick={handleExtraction}
              disabled={isExtracting}
              className="w-full bg-purple-600 hover:bg-purple-700 text-white font-medium py-2 rounded-lg flex items-center justify-center gap-2 transition-colors disabled:opacity-50"
            >
              {isExtracting ? <Loader2 className="animate-spin" size={18} /> : <Sparkles size={18} />}
              {isExtracting ? 'Analyzing...' : 'Extract Reactions with Gemini'}
            </button>
          </div>
        </div>

        {/* Right Col: Reactions List */}
        <div className="flex flex-col h-full">
          <div className="flex justify-between items-center mb-4">
             <label className="text-sm font-semibold text-slate-700">Identified Adverse Reactions</label>
             <button onClick={addEmptyReaction} className="text-xs text-teal-600 hover:text-teal-700 font-medium">+ Add Manually</button>
          </div>

          <div className="flex-1 overflow-y-auto bg-slate-50 rounded-xl border border-slate-200 p-4 space-y-3 max-h-[600px]">
            {reactions.length === 0 && (
              <div className="h-full flex flex-col items-center justify-center text-slate-400 p-8 text-center">
                <FileText size={48} className="mb-4 opacity-20" />
                <p>No reactions listed yet.</p>
                <p className="text-xs mt-2">Use AI extraction or add manually.</p>
              </div>
            )}

            {reactions.map((reaction, idx) => (
              <div key={idx} className="bg-white p-3 rounded-lg shadow-sm border border-slate-200 flex flex-col gap-2">
                <div className="flex justify-between items-start">
                   <input 
                    type="text" 
                    value={reaction.name}
                    onChange={(e) => updateReaction(idx, 'name', e.target.value)}
                    className="font-medium text-slate-800 border-none focus:ring-0 p-0 w-full"
                    placeholder="Reaction Name"
                   />
                   <button onClick={() => removeReaction(idx)} className="text-slate-300 hover:text-red-500"><X size={16}/></button>
                </div>
                <div className="flex items-center gap-4 text-sm">
                   <div className="flex-1">
                      <label className="text-xs text-slate-400 block">Frequency Text</label>
                      <input 
                        type="text" 
                        value={reaction.frequencyText || ''}
                        onChange={(e) => updateReaction(idx, 'frequencyText', e.target.value)}
                        className="w-full text-slate-600 bg-slate-50 rounded px-2 py-1 border-none"
                      />
                   </div>
                   <div className="w-24">
                      <label className="text-xs text-slate-400 block">Rate (0-1)</label>
                      <input 
                        type="number" 
                        step="0.0001"
                        value={reaction.baselineRate}
                        onChange={(e) => updateReaction(idx, 'baselineRate', parseFloat(e.target.value))}
                        className="w-full font-mono text-teal-600 bg-teal-50 rounded px-2 py-1 text-right border-none"
                      />
                   </div>
                </div>
              </div>
            ))}
          </div>

          <div className="mt-6 pt-6 border-t border-slate-100 flex justify-end gap-3">
            <button onClick={onCancel} className="px-6 py-2 text-slate-600 font-medium hover:bg-slate-100 rounded-lg transition-colors">Cancel</button>
            <button onClick={handleSave} className="px-6 py-2 bg-teal-600 hover:bg-teal-700 text-white font-medium rounded-lg shadow-sm flex items-center gap-2 transition-colors">
              <Save size={18} />
              Save Drug Profile
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DrugForm;

import React, { useState, useEffect } from 'react';
import { Drug, QuarterlyData } from '../types';
import { Save, AlertCircle } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

interface DataEntryProps {
  drugs: Drug[];
  onAddData: (drugId: string, data: QuarterlyData) => void;
}

const DataEntry: React.FC<DataEntryProps> = ({ drugs, onAddData }) => {
  const [selectedDrugId, setSelectedDrugId] = useState<string>('');
  const [quarterLabel, setQuarterLabel] = useState<string>('');
  const [salesVolume, setSalesVolume] = useState<string>('');
  const [counts, setCounts] = useState<Record<string, number>>({});

  const selectedDrug = drugs.find(d => d.id === selectedDrugId);

  // Set default quarter
  useEffect(() => {
    const now = new Date();
    const q = Math.floor((now.getMonth() + 3) / 3);
    setQuarterLabel(`${now.getFullYear()}-Q${q}`);
  }, []);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedDrug) return;
    if (!salesVolume || parseFloat(salesVolume) <= 0) return alert("Please enter valid sales figures.");

    const newData: QuarterlyData = {
      id: uuidv4(),
      quarterLabel,
      salesVolume: parseFloat(salesVolume),
      reactionCounts: counts
    };

    onAddData(selectedDrug.id, newData);

    // Reset form partial
    setSalesVolume('');
    setCounts({});
    alert("Data saved successfully!");
  };

  const handleCountChange = (reactionId: string, val: string) => {
    setCounts(prev => ({
      ...prev,
      [reactionId]: parseInt(val) || 0
    }));
  };

  if (drugs.length === 0) {
    return (
      <div className="text-center p-12 bg-white rounded-xl shadow-sm border border-slate-200">
        <AlertCircle className="mx-auto text-slate-300 mb-4" size={48} />
        <h3 className="text-lg font-medium text-slate-700">No Drugs Available</h3>
        <p className="text-slate-500">Please add a drug profile first to enter data.</p>
      </div>
    );
  }

  return (
    <div className="max-w-3xl mx-auto">
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-6 border-b border-slate-100 bg-slate-50/50">
          <h3 className="text-lg font-bold text-slate-800">New Quarterly Report</h3>
          <p className="text-sm text-slate-500">Enter sales figures and collected adverse reaction cases.</p>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-8">
          <div className="grid md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-2">Select Drug</label>
              <select 
                className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none"
                value={selectedDrugId}
                onChange={e => {
                  setSelectedDrugId(e.target.value);
                  setCounts({});
                }}
              >
                <option value="">-- Choose Drug --</option>
                {drugs.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-2">Quarter</label>
              <input 
                type="text" 
                className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none"
                value={quarterLabel}
                onChange={e => setQuarterLabel(e.target.value)}
                placeholder="e.g. 2024-Q1"
              />
            </div>
          </div>

          <div className="bg-blue-50 p-4 rounded-lg border border-blue-100">
            <label className="block text-sm font-bold text-blue-800 mb-2">Total Sales Volume (Denominator)</label>
            <div className="relative">
              <input 
                type="number" 
                min="1"
                className="w-full pl-4 pr-12 py-3 border border-blue-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-lg font-mono text-blue-900 placeholder-blue-300"
                value={salesVolume}
                onChange={e => setSalesVolume(e.target.value)}
                placeholder="0"
              />
              <span className="absolute right-4 top-3.5 text-blue-400 text-sm font-medium">UNITS</span>
            </div>
            <p className="text-xs text-blue-600 mt-2">
              This figure represents the total exposure (e.g., boxes sold, prescriptions filled) for the selected quarter.
            </p>
          </div>

          {selectedDrug && (
            <div className="space-y-4">
              <h4 className="font-semibold text-slate-700 border-b border-slate-100 pb-2">
                Collected Adverse Reaction Cases
              </h4>
              <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
                {selectedDrug.reactions.map(reaction => (
                  <div key={reaction.id} className="bg-slate-50 p-4 rounded-lg border border-slate-200 flex flex-col">
                    <span className="text-sm font-medium text-slate-700 mb-1 truncate" title={reaction.name}>{reaction.name}</span>
                    <span className="text-xs text-slate-400 mb-3">Baseline: {(reaction.baselineRate * 100).toFixed(3)}%</span>
                    <div className="mt-auto">
                      <label className="text-xs font-semibold text-slate-500 uppercase">Case Count</label>
                      <input 
                        type="number" 
                        min="0"
                        className="w-full mt-1 px-3 py-2 border border-slate-300 rounded focus:border-teal-500 outline-none"
                        value={counts[reaction.id] || ''}
                        onChange={e => handleCountChange(reaction.id, e.target.value)}
                        placeholder="0"
                      />
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          <div className="pt-4 flex justify-end">
            <button 
              type="submit" 
              disabled={!selectedDrug || !salesVolume}
              className="bg-teal-600 hover:bg-teal-700 text-white font-bold py-3 px-8 rounded-lg shadow-lg shadow-teal-600/20 flex items-center gap-2 transition-all disabled:opacity-50 disabled:shadow-none"
            >
              <Save size={20} />
              Submit Quarterly Data
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default DataEntry;

import React, { useState } from 'react';
import { Drug, AdverseReaction } from '../types';
import { AlertTriangle, TrendingUp, CheckCircle, Search } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, ReferenceLine } from 'recharts';

interface AnalysisViewProps {
  drugs: Drug[];
}

const AnalysisView: React.FC<AnalysisViewProps> = ({ drugs }) => {
  const [selectedDrugId, setSelectedDrugId] = useState<string>(drugs.length > 0 ? drugs[0].id : '');
  const [selectedQuarterId, setSelectedQuarterId] = useState<string>('');

  const selectedDrug = drugs.find(d => d.id === selectedDrugId);

  // Default to most recent quarter if not selected
  const currentQuarterData = selectedDrug?.history.find(h => 
    selectedQuarterId ? h.id === selectedQuarterId : true
  ) || (selectedDrug?.history.length ? selectedDrug.history[selectedDrug.history.length - 1] : null);

  // Prepare chart data
  const chartData = selectedDrug && currentQuarterData ? selectedDrug.reactions.map(reaction => {
    const caseCount = currentQuarterData.reactionCounts[reaction.id] || 0;
    const actualRate = caseCount / currentQuarterData.salesVolume;
    const isAlert = actualRate > reaction.baselineRate;

    return {
      name: reaction.name,
      Baseline: reaction.baselineRate * 100, // Convert to percentage
      Actual: actualRate * 100,
      isAlert,
      caseCount,
      baselineRateRaw: reaction.baselineRate,
      actualRateRaw: actualRate
    };
  }) : [];

  // Sort by highest risk ratio (Actual / Baseline)
  const sortedRisks = [...chartData].sort((a, b) => 
    (b.Actual / b.Baseline || 0) - (a.Actual / a.Baseline || 0)
  );

  const alerts = sortedRisks.filter(r => r.isAlert);

  if (drugs.length === 0) {
    return <div className="text-center p-12 text-slate-400">No drug data available for analysis.</div>;
  }

  return (
    <div className="space-y-6">
      {/* Controls */}
      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-col md:flex-row gap-4 items-center justify-between">
         <div className="flex items-center gap-4 w-full md:w-auto">
            <div className="relative w-full md:w-64">
              <Search className="absolute left-3 top-2.5 text-slate-400" size={18} />
              <select 
                value={selectedDrugId} 
                onChange={e => { setSelectedDrugId(e.target.value); setSelectedQuarterId(''); }}
                className="w-full pl-10 pr-4 py-2 border border-slate-300 rounded-lg appearance-none bg-white focus:ring-2 focus:ring-teal-500 outline-none font-medium text-slate-700"
              >
                {drugs.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
              </select>
