import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import DrugForm from './components/DrugForm';
import DataEntry from './components/DataEntry';
import AnalysisView from './components/AnalysisView';
import { Drug, ViewState, QuarterlyData } from './types';
import { v4 as uuidv4 } from 'uuid';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('dashboard');

  // Initialize with some dummy data if empty, otherwise load from local storage
  const [drugs, setDrugs] = useState<Drug[]>(() => {
    const saved = localStorage.getItem('pharmaGuardData');
    if (saved) return JSON.parse(saved);
    return []; 
  });

  // Persistence
  useEffect(() => {
    localStorage.setItem('pharmaGuardData', JSON.stringify(drugs));
  }, [drugs]);

  const handleAddDrug = (newDrug: Drug) => {
    setDrugs([...drugs, newDrug]);
    setCurrentView('dashboard');
  };

  const handleAddQuarterlyData = (drugId: string, data: QuarterlyData) => {
    setDrugs(prev => prev.map(d => {
      if (d.id === drugId) {
        return {
          ...d,
          history: [...d.history, data]
        };
      }
      return d;
    }));
  };

  const renderContent = () => {
    switch (currentView) {
      case 'dashboard':
        return <Dashboard drugs={drugs} onNavigate={setCurrentView} />;
      case 'add-drug':
        return <DrugForm onSave={handleAddDrug} onCancel={() => setCurrentView('dashboard')} />;
      case 'entry':
        return <DataEntry drugs={drugs} onAddData={handleAddQuarterlyData} />;
      case 'analysis':
        return <AnalysisView drugs={drugs} />;
      default:
        return <Dashboard drugs={drugs} onNavigate={setCurrentView} />;
    }
  };

  return (
    <Layout currentView={currentView} setView={setCurrentView}>
      {renderContent()}
    </Layout>
  );
};

