{
  "name": "PV AE Master Generator",
  "description": "Pharmacovigilance tool to extract Adverse Event Master Files from package inserts using strict mapping rules.",
  "requestFramePermissions": [
    "camera"
  ]
}

import { GoogleGenAI, Type, Schema } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
你是一位藥品安全監視（PV）資料工程助理。請從使用者提供的「仿單不良反應表格」（可能是圖片或文字）中，建立可匯入資料庫的 AE 主檔 JSON。請嚴格遵守以下規則，輸出繁體中文。

目標輸出結構：
1. product_name（字串）
2. label_version_date（若無則留空）
3. frequency_legend（仿單頻率分類定義原文，盡量保留）
4. ae_master（陣列，每一筆代表一個 AE term）：
   - soc（系統器官分類，字串）
   - ae_term_raw（仿單原文 AE term，字串）
   - ae_terms_split（字串陣列：若同一格有多個 AE，必須逐條拆分）
   - label_frequency_text（如：常見/不常見…，字串）
   - label_threshold_upper_pct（數字：以「上限%」做門檻）
   - mapping_rule_note（你如何推導門檻：上限/下限/固定值）

解析規則：
1. 「不良反應」欄位若含多個項目，請用以下分隔符拆成多個 ae_terms_split：
   - 頓號「、」、分號「；」、逗號、換行、括號外的連續列舉
   - 英文括號內容要保留在 ae_term_raw，但 ae_terms_split 需同時產出：中文名（若有）、英文名（若有）。
     例：γ麩胺醯轉移酶(gamma glutamyl transferase)升高 → split 為 ["γ麩胺醯轉移酶升高","gamma glutamyl transferase increased"]

2. 仿單頻率分類 → 門檻% 的映射，請使用「上限%」：
   - 十分常見 (≥1/10) → 10% (依照使用者特定規則：100*(1/10)=10%)
   - 常見 (≥1/100 至 <1/10) → 10%
   - 不常見 (≥1/1,000 至 <1/100) → 1%
   - 罕見 (≥1/10,000 至 <1/1,000) → 0.1%
   - 十分罕見 (<1/10,000) → 0.01%
   - 若表格只寫「常見/不常見」沒有區間，也請套用以上門檻。

3. 必須做基本清理：
   - 去除多餘空白、全形/半形統一
   - 若同一 AE term 在不同 SOC 重複出現，仍要各自保留（以 SOC+AE 為鍵）
   - 如果有你不確定的拆分或解讀，請在 mapping_rule_note 中用「需要人工確認」標記。
`;

// Define the response schema using strict typing
const outputSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    product_name: { type: Type.STRING, description: "Name of the drug product" },
    label_version_date: { type: Type.STRING, description: "Date of the label version if available" },
    frequency_legend: { type: Type.STRING, description: "Original text defining frequency categories" },
    ae_master: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          soc: { type: Type.STRING, description: "System Organ Class" },
          ae_term_raw: { type: Type.STRING, description: "Original AE term from the text" },
          ae_terms_split: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "Split terms for database indexing"
          },
          label_frequency_text: { type: Type.STRING, description: "Frequency category text (e.g., Common)" },
          label_threshold_upper_pct: { type: Type.NUMBER, description: "Numeric upper threshold percentage" },
          mapping_rule_note: { type: Type.STRING, description: "Explanation of the mapping logic used" },
        },
        required: ["soc", "ae_term_raw", "ae_terms_split", "label_frequency_text", "label_threshold_upper_pct", "mapping_rule_note"]
      }
    }
  },
  required: ["product_name", "ae_master"]
};

export async function extractAEMaster(textInput: string, imageBase64?: string) {
  const parts: any[] = [];

  if (imageBase64) {
    parts.push({
      inlineData: {
        mimeType: "image/png", // Assuming PNG for generic base64 handling, logic works for jpeg too usually
        data: imageBase64
      }
    });
  }

  if (textInput) {
    parts.push({ text: textInput });
  }

  if (parts.length === 0) {
    throw new Error("No input provided");
  }

  const modelId = imageBase64 ? "gemini-3-flash-preview" : "gemini-3-flash-preview";

  const response = await ai.models.generateContent({
    model: modelId,
    contents: {
      role: 'user',
      parts: parts
    },
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: outputSchema,
      temperature: 0.1, // Low temperature for factual extraction
    }
  });

  return JSON.parse(response.text || "{}");
}

