    const file = e.target.files?.[0];
    if (file) {
      setImageFile(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleProcess = async () => {
    if (!textInput && !imageFile) {
      setError("請提供文字描述或上傳圖片");
      return;
    }

    setLoading(true);
    setError(null);
    setResult(null);

