      .filter(r => r.term.trim() !== '' && r.count.trim() !== '')
      .map(r => ({
        term: r.term,
        count: parseInt(r.count, 10) || 0
      }));

    if (validCounts.length === 0) {
      alert("請至少輸入一筆 AE 案例");
      return;
    }

    const report = performAnalysis(masterResult, {
      quarter,
      exposure_value: val,
      exposure_unit: exposureUnit,
      ae_counts: validCounts
    });

