                      <button onClick={() => setActiveGenTab('visual')} className={`px-2 py-1 text-xs rounded ${activeGenTab === 'visual' ? 'bg-slate-100 text-brand-600 font-bold' : 'text-slate-500'}`}>預覽</button>
                      <button onClick={() => setActiveGenTab('json')} className={`px-2 py-1 text-xs rounded ${activeGenTab === 'json' ? 'bg-slate-100 text-brand-600 font-bold' : 'text-slate-500'}`}>JSON</button>
