export interface AeMasterItem {
  soc: string;
  ae_term_raw: string;
  ae_terms_split: string[];
  label_frequency_text: string;
  label_threshold_upper_pct: number;
  mapping_rule_note: string;
}

export interface QuarterlyInput {
  quarter: string;
  exposure_value: number;
  exposure_unit: string;
  ae_counts: { term: string; count: number }[];
}

export interface AnalysisOptions {
  includeAllMasterTerms?: boolean;
}

export interface AnalysisResultRow {
  soc: string;
  ae_term: string; // The matched split term or input term
  frequency_category: string;
  threshold_pct: number;
  count: number;
  exposure_display: string;
  incidence_rate_pct: number;
  status: 'alert' | 'warning' | 'normal' | 'unmatched';
  original_master?: AeMasterItem;
}

export interface AnalysisReport {
  rows: AnalysisResultRow[];
  unmatched: string[];
  alerts: AnalysisResultRow[];
}

// Normalize string for matching (lowercase, trim, remove extra spaces)
const normalize = (str: string) => str.toLowerCase().trim().replace(/\s+/g, ' ');

export function performAnalysis(
  masterData: { ae_master: AeMasterItem[] },
  input: QuarterlyInput,
  options: AnalysisOptions = {}
): AnalysisReport {
  const { exposure_value, exposure_unit, ae_counts } = input;
  const { includeAllMasterTerms } = options;

  // 1. Build lookup map from Master Data
  // Map normalized split term -> Master Item
  const termMap = new Map<string, { item: AeMasterItem; specificTerm: string }>();
  // Track used master terms to avoid duplicates when backfilling
  const usedMasterTerms = new Set<string>();

  masterData.ae_master.forEach(item => {
    item.ae_terms_split.forEach(splitTerm => {
      termMap.set(normalize(splitTerm), { item, specificTerm: splitTerm });
    });
  });

  const rows: AnalysisResultRow[] = [];
  const unmatched: string[] = [];

  // 2. Process each input count
  ae_counts.forEach(({ term, count }) => {
    const normalizedInput = normalize(term);
    const match = termMap.get(normalizedInput);

    if (!match) {
      unmatched.push(term);
      rows.push({
        soc: 'Unknown',
        ae_term: term,
        frequency_category: 'N/A',
        threshold_pct: 0,
        count,
        exposure_display: `${exposure_value} ${exposure_unit}`,
        incidence_rate_pct: (count / exposure_value) * 100,
        status: 'unmatched'
      });
      return;
    }

    // Mark this term as used
    usedMasterTerms.add(normalizedInput);

    const { item, specificTerm } = match;
    const incidenceRate = (count / exposure_value) * 100;

    // 3. Determine Status based on rules
    let status: AnalysisResultRow['status'] = 'normal';

    if (count < 1) {
      // Rule: Count < 1 (0) -> Normal (Display only)
      status = 'normal';
    } else if (count < 3) {
      // Rule: 1 <= Count < 3 -> Yellow warning (Caution for low count)
      status = 'warning';
    } else if (incidenceRate > item.label_threshold_upper_pct) {
      // Rule: Count >= 3 AND Rate > Threshold -> Red Alert
      status = 'alert';
    } else {
      // Count >= 3 but Rate <= Threshold -> Normal
      status = 'normal';
    }

    rows.push({
      soc: item.soc,
      ae_term: specificTerm, // Use the official split term found
      frequency_category: item.label_frequency_text,
      threshold_pct: item.label_threshold_upper_pct,
      count,
      exposure_display: `${exposure_value} ${exposure_unit}`,
      incidence_rate_pct: incidenceRate,
      status,
      original_master: item
    });
  });

  // 3. (Optional) Backfill remaining master terms with 0 count
  if (includeAllMasterTerms) {
    masterData.ae_master.forEach(item => {
      item.ae_terms_split.forEach(splitTerm => {
        const normalized = normalize(splitTerm);
        if (!usedMasterTerms.has(normalized)) {
          // Add as normal row with 0 count
          rows.push({
            soc: item.soc,
            ae_term: splitTerm,
            frequency_category: item.label_frequency_text,
            threshold_pct: item.label_threshold_upper_pct,
            count: 0,
            exposure_display: `${exposure_value} ${exposure_unit}`,
            incidence_rate_pct: 0,
            status: 'normal',
            original_master: item
          });
          // Mark used to prevent duplicates if term appears multiple times in master
          usedMasterTerms.add(normalized);
        }
      });
    });
  }

  // Sort rows: Alerts first (desc rate), then Warnings, then Normal, then Unmatched
  rows.sort((a, b) => {
    const priority = { alert: 0, warning: 1, unmatched: 2, normal: 3 };
    if (priority[a.status] !== priority[b.status]) {
      return priority[a.status] - priority[b.status];
    }
    // If status is same, sort by rate descending
    if (b.incidence_rate_pct !== a.incidence_rate_pct) {
      return b.incidence_rate_pct - a.incidence_rate_pct;
    }
    // Secondary sort by AE term name for stability (especially for 0 rate items)
    return a.ae_term.localeCompare(b.ae_term);
  });

  const alerts = rows.filter(r => r.status === 'alert');

  return { rows, unmatched, alerts };
}

import React, { useState, useEffect } from 'react';
import { extractAEMaster } from './services/gemini';
import { performAnalysis, AnalysisReport } from './services/analysis';
import { db, Product, LabelAeMaster, QuarterlyAeMonitor } from './services/db';
import { Clipboard, Upload, FileText, Activity, AlertCircle, Check, Database, BarChart3, Plus, Trash2, ArrowRight, Save, FolderOpen, Table, History, ToggleLeft, ToggleRight } from 'lucide-react';

export default function App() {
  // Navigation State
  const [activeMode, setActiveMode] = useState<'generator' | 'monitor' | 'library'>('generator');

  // Generator State
  const [textInput, setTextInput] = useState('');
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [masterResult, setMasterResult] = useState<any>(null); // The JSON from Gemini
  const [error, setError] = useState<string | null>(null);
  const [activeGenTab, setActiveGenTab] = useState<'visual' | 'json'>('visual');
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved'>('idle');

  // Monitoring State
  const [quarter, setQuarter] = useState('2025Q1');
  const [exposureVal, setExposureVal] = useState<string>('');
  const [exposureUnit, setExposureUnit] = useState('人年');
  const [inputCounts, setInputCounts] = useState<{term: string, count: string}[]>([{term: '', count: ''}]);
  const [analysisReport, setAnalysisReport] = useState<AnalysisReport | null>(null);
  const [showAllTerms, setShowAllTerms] = useState(false);

  // Database Integration State
  const [savedProducts, setSavedProducts] = useState<Product[]>([]);
  const [selectedProductId, setSelectedProductId] = useState<string>('');
  const [monitorSaveStatus, setMonitorSaveStatus] = useState<'idle' | 'saved'>('idle');

  // Refresh products list
  useEffect(() => {
    setSavedProducts(db.getProducts());
  }, [activeMode]);

  // Effect to re-run analysis when showAllTerms toggles
  useEffect(() => {
    if (analysisReport && masterResult) {
      runAnalysis();
    }
  }, [showAllTerms]);

  // --- Handlers for Generator ---
  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setImageFile(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleProcess = async () => {
    if (!textInput && !imageFile) {
      setError("請提供文字描述或上傳圖片");
      return;
    }

    setLoading(true);
    setError(null);
    setMasterResult(null);
    setSaveStatus('idle');

    try {
      let base64Image = undefined;
      if (imageFile) {
        base64Image = await new Promise<string>((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = () => {
            const result = reader.result as string;
            const base64 = result.split(',')[1];
            resolve(base64);
          };
          reader.onerror = reject;
          reader.readAsDataURL(imageFile);
        });
      }

      const data = await extractAEMaster(textInput, base64Image);
      setMasterResult(data);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "發生錯誤，請檢查 API Key 或重試。");
    } finally {
      setLoading(false);
    }
  };

  const handleSaveToDb = () => {
    if (!masterResult) return;
    try {
      const newId = db.saveExtractedMaster(masterResult);
      setSaveStatus('saved');
      setSavedProducts(db.getProducts());
      // Auto select this new product if user goes to monitor tab
      setSelectedProductId(newId);
    } catch (e) {
      console.error(e);
      alert("儲存失敗");
    }
  };

  // --- Handlers for Monitoring ---
  const handleLoadProduct = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const pid = e.target.value;
    setSelectedProductId(pid);
    if (pid) {
      const analysisFormat = db.getMasterForAnalysis(pid);
      setMasterResult(analysisFormat);
      setAnalysisReport(null); // Clear previous report
      setMonitorSaveStatus('idle');
    } else {
      setMasterResult(null);
    }
  };

  const handleAddRow = () => {
    setInputCounts([...inputCounts, { term: '', count: '' }]);
  };

  const handleRemoveRow = (idx: number) => {
    setInputCounts(inputCounts.filter((_, i) => i !== idx));
  };

  const handleInputChange = (idx: number, field: 'term' | 'count', value: string) => {
    const newRows = [...inputCounts];
    newRows[idx] = { ...newRows[idx], [field]: value };
    setInputCounts(newRows);
  };

  const handleQuickAddTerm = (term: string) => {
    const lastRow = inputCounts[inputCounts.length - 1];
    if (!lastRow.term && !lastRow.count) {
      handleInputChange(inputCounts.length - 1, 'term', term);
    } else {
      setInputCounts([...inputCounts, { term, count: '' }]);
    }
  };

  const runAnalysis = () => {
    if (!masterResult) {
      alert("請先載入產品或產生主檔");
      return;
    }
    const val = parseFloat(exposureVal);
    if (isNaN(val) || val <= 0) {
      alert("請輸入有效的暴露量數值");
      return;
    }

    // Filter valid rows: Must have a term name. Count defaults to 0 if empty.
    const validCounts = inputCounts
      .filter(r => r.term.trim() !== '') 
      .map(r => ({
        term: r.term,
        count: parseInt(r.count, 10) || 0
      }));

    // Allow analysis even if validCounts is empty (Report will show 0 cases)
    const report = performAnalysis(masterResult, {
      quarter,
      exposure_value: val,
      exposure_unit: exposureUnit,
      ae_counts: validCounts
    }, {
      includeAllMasterTerms: showAllTerms
    });

    setAnalysisReport(report);
    setMonitorSaveStatus('idle');
  };

  const handleSaveAnalysis = () => {
    if (!analysisReport || !selectedProductId) {
      alert("需選擇產品並執行分析後才能儲存");
      return;
    }

    const records: QuarterlyAeMonitor[] = [];
    const now = new Date().toISOString();

    analysisReport.rows.forEach(row => {
      let status: 'normal' | 'yellow' | 'red' = 'normal';
      if (row.status === 'alert') status = 'red';
      if (row.status === 'warning') status = 'yellow';

      // If status is normal and count is 0 (from "show all"), we might not want to save it to DB to save space?
      // Or we save it because the user explicitly included it?
      // The requirement doesn't specify saving behavior for zero-count items.
      // Usually zero-count items are for display only. Saving them floods the DB.
      // I'll save them if they are in the report, to faithfully record the report state.

      records.push({
        product_id: selectedProductId,
        quarter: quarter,
        exposure_value: parseFloat(exposureVal),
        exposure_unit: exposureUnit,
        ae_term: row.ae_term,
        count: row.count,
        rate_pct: row.incidence_rate_pct,
        threshold_pct: row.threshold_pct,
        status: status,
        generated_at: now
      });
    });

    if (analysisReport.rows.length > 0) {
       db.saveQuarterlyAeMonitors(records);
    }

    setMonitorSaveStatus('saved');
  };

  const handleDeleteProduct = (pid: string) => {
    if(confirm('確定要刪除此產品及其所有相關資料嗎？')) {
      db.deleteProduct(pid);
      setSavedProducts(db.getProducts());
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-800 font-sans">
      {/* Top Navigation */}
      <nav className="bg-slate-900 text-white shadow-md sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-brand-500 p-2 rounded text-white">
              <Activity size={20} />
            </div>
            <span className="font-bold text-lg tracking-tight">PV 智慧監測平台</span>
          </div>
          <div className="flex gap-1 bg-slate-800 p-1 rounded-lg">
            <button
              onClick={() => setActiveMode('generator')}
              className={`px-3 py-2 text-sm font-medium rounded-md transition-all flex items-center gap-2 ${
                activeMode === 'generator' ? 'bg-brand-600 text-white shadow' : 'text-slate-400 hover:text-white'
              }`}
            >
              <FileText size={16}/>
              1. AE 主檔生成
            </button>
            <button
              onClick={() => setActiveMode('monitor')}
              className={`px-3 py-2 text-sm font-medium rounded-md transition-all flex items-center gap-2 ${
                activeMode === 'monitor' ? 'bg-brand-600 text-white shadow' : 'text-slate-400 hover:text-white'
              }`}
            >
              <Activity size={16}/>
              2. 訊號監測
            </button>
            <button
              onClick={() => setActiveMode('library')}
              className={`px-3 py-2 text-sm font-medium rounded-md transition-all flex items-center gap-2 ${
                activeMode === 'library' ? 'bg-brand-600 text-white shadow' : 'text-slate-400 hover:text-white'
              }`}
            >
              <Database size={16}/>
              資料庫管理
            </button>
          </div>
        </div>
      </nav>

      <div className="max-w-6xl mx-auto p-4 md:p-8">

        {/* --- MODE 1: GENERATOR --- */}
        {activeMode === 'generator' && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 space-y-6">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
              <div className="flex items-center gap-3 mb-6">
                <div className="w-10 h-10 rounded-full bg-brand-100 flex items-center justify-center text-brand-600">
                  <FileText size={20} />
                </div>
                <div>
                  <h2 className="font-bold text-lg text-slate-900">仿單資料提取</h2>
                  <p className="text-slate-500 text-sm">上傳圖片或貼上文字，自動轉換為標準 JSON 主檔</p>
                </div>
              </div>

              <div className="grid lg:grid-cols-2 gap-8">
                {/* Input Area */}
                <div className="space-y-4">
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-2">仿單文字 (Text)</label>
                    <textarea
                      value={textInput}
                      onChange={(e) => setTextInput(e.target.value)}
                      className="w-full h-32 p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none text-sm"
                      placeholder="貼上仿單內容..."
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-2">表格圖片 (Image)</label>
                    <div className="border-2 border-dashed border-slate-300 rounded-lg p-4 hover:bg-slate-50 text-center cursor-pointer relative transition-colors">
                      <input type="file" accept="image/*" onChange={handleImageChange} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" />
                      {imagePreview ? (
                        <div className="relative inline-block">
                          <img src={imagePreview} alt="Preview" className="max-h-32 rounded shadow-sm" />
                          <button onClick={(e) => { e.preventDefault(); setImageFile(null); setImagePreview(null); }} className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 shadow-md hover:bg-red-600">
                            <Trash2 size={12} />
                          </button>
                        </div>
                      ) : (
                        <div className="text-slate-400 py-4"><Upload size={24} className="mx-auto mb-2" />點擊上傳圖片</div>
                      )}
                    </div>
                  </div>
                  <button
                    onClick={handleProcess}
                    disabled={loading}
                    className="w-full py-3 bg-brand-600 hover:bg-brand-700 text-white rounded-lg font-medium shadow-lg shadow-brand-200 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                  >
                    {loading ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : <Database size={18} />}
                    {loading ? 'AI 解析中...' : '產生 AE Master'}
                  </button>
                  {error && <div className="p-3 bg-red-50 text-red-600 rounded-lg text-sm flex items-center gap-2"><AlertCircle size={16}/>{error}</div>}
                </div>

                {/* Result Area */}
                <div className="flex flex-col h-full bg-slate-50 rounded-lg border border-slate-200 overflow-hidden min-h-[400px]">
                  <div className="flex justify-between items-center px-4 py-2 border-b border-slate-200 bg-white">
                    <span className="font-semibold text-sm">解析結果</span>
                    <div className="flex gap-2">
                       {masterResult && (
                         <button 
                           onClick={handleSaveToDb}
                           disabled={saveStatus === 'saved'}
                           className={`px-3 py-1 text-xs rounded font-medium flex items-center gap-1 transition-colors ${saveStatus === 'saved' ? 'bg-green-100 text-green-700' : 'bg-brand-600 text-white hover:bg-brand-700'}`}
                         >
                           {saveStatus === 'saved' ? <Check size={14}/> : <Save size={14}/>}
                           {saveStatus === 'saved' ? '已儲存' : '存入資料庫'}
                         </button>
                       )}
                    </div>
                  </div>
                  <div className="flex-1 overflow-auto p-4 relative">
                    {!masterResult ? (
                      <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-300">
                        <Database size={40} className="mb-2 opacity-20" />
                        <p className="text-sm">尚無資料</p>
                      </div>
                    ) : (
                      <div className="space-y-4">
                        <div className="grid grid-cols-2 gap-2 text-xs bg-white p-3 rounded border border-slate-200">
                          <div><span className="text-slate-400 block">Product</span>{masterResult.product_name || '-'}</div>
                          <div><span className="text-slate-400 block">Version</span>{masterResult.label_version_date || '-'}</div>
                        </div>
