                                 <div className="font-medium text-slate-800">{item.ae_terms_split[0]}</div>
                                 <div className="text-xs text-slate-500">{item.soc} • {item.label_frequency_text}</div>
                               </div>
                               <div className="text-brand-600 font-mono font-bold">{item.label_threshold_upper_pct}%</div>
                             </div>
                           ))}
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

