  // Database Integration State
  const [savedProducts, setSavedProducts] = useState<Product[]>([]);
  const [selectedProductId, setSelectedProductId] = useState<string>('');
  const [monitorSaveStatus, setMonitorSaveStatus] = useState<'idle' | 'saved'>('idle');
  // Trigger to force re-render of library view when DB changes
  const [dbUpdateTrigger, setDbUpdateTrigger] = useState(0);

  // Refresh products list
  useEffect(() => {
    setSavedProducts(db.getProducts());
  }, [activeMode, dbUpdateTrigger]);

  // Effect to re-run analysis when showAllTerms toggles
  useEffect(() => {
    if (analysisReport && masterResult) {
      runAnalysis();
    }
  }, [showAllTerms]);

  // --- Handlers for Generator ---
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setUploadedFile(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setFileDataUrl(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleClearFile = (e: React.MouseEvent) => {
    e.preventDefault();
    setUploadedFile(null);
    setFileDataUrl(null);
  };

  const handleProcess = async () => {
    if (!textInput && !uploadedFile) {
      setError("請提供文字描述或上傳檔案");
      return;
    }

    setLoading(true);
    setError(null);
    setMasterResult(null);
    setCurrentExtractionProductId(null); // Reset ID for new extraction
    setSaveStatus('idle');

    try {
      let fileInput: FileInput | undefined = undefined;
      if (uploadedFile && fileDataUrl) {
        // extract base64 from dataUrl (remove "data:xxxx;base64,")
        const base64 = fileDataUrl.split(',')[1];
        fileInput = {
          data: base64,
          mimeType: uploadedFile.type
        };
      }

      const data = await extractAEMaster(textInput, fileInput);
      setMasterResult(data);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "發生錯誤，請檢查 API Key 或重試。");
    } finally {
      setLoading(false);
    }
  };

  // --- Master Result Editing Handlers ---

  const handleResultChange = (index: number, field: string, value: any) => {
    if (!masterResult) return;
    const newAeMaster = [...masterResult.ae_master];

    if (field === 'ae_terms_split') {
      // Input comes as string, split by comma for storage
      newAeMaster[index] = {
        ...newAeMaster[index],
        ae_terms_split: value.split(/[,，、;]+/).map((t: string) => t.trim()).filter((t: string) => t)
      };
    } else {
      newAeMaster[index] = { ...newAeMaster[index], [field]: value };
    }

    setMasterResult({ ...masterResult, ae_master: newAeMaster });
    setSaveStatus('idle'); // Reset save status if modified
  };

  const handleDeleteResultItem = (index: number) => {
    if (!masterResult) return;
    const newAeMaster = masterResult.ae_master.filter((_: any, i: number) => i !== index);
    setMasterResult({ ...masterResult, ae_master: newAeMaster });
    setSaveStatus('idle');
  };

  const handleAddResultItem = () => {
    if (!masterResult) return;
    const newItem = {
      soc: "",
      ae_term_raw: "",
      ae_terms_split: [],
      label_frequency_text: "",
      label_threshold_upper_pct: 0,
      mapping_rule_note: "Manual Entry"
    };
    setMasterResult({ 
      ...masterResult, 
      ae_master: [...(masterResult.ae_master || []), newItem] 
    });
    setSaveStatus('idle');
  };

  const handleSaveToDb = () => {
    if (!masterResult) return;
    try {
      // If we already saved this session, update the existing ID. Otherwise undefined (create new).
      const newId = db.saveExtractedMaster(masterResult, currentExtractionProductId || undefined);

      setCurrentExtractionProductId(newId);
      setSaveStatus('saved');
      setSavedProducts(db.getProducts());

      // Auto select this new product if user goes to monitor tab
      setSelectedProductId(newId);
    } catch (e) {
      console.error(e);
      alert("儲存失敗");
    }
  };

  // --- Handlers for Monitoring ---
  const handleLoadProduct = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const pid = e.target.value;
    setSelectedProductId(pid);
    if (pid) {
      const analysisFormat = db.getMasterForAnalysis(pid);
      setMasterResult(analysisFormat);
      setAnalysisReport(null); // Clear previous report
      setMonitorSaveStatus('idle');
    } else {
      setMasterResult(null);
    }
  };

  const handleAddRow = () => {
    setInputCounts([...inputCounts, { term: '', count: '' }]);
  };

  const handleRemoveRow = (idx: number) => {
    setInputCounts(inputCounts.filter((_, i) => i !== idx));
  };

  const handleInputChange = (idx: number, field: 'term' | 'count', value: string) => {
    const newRows = [...inputCounts];
    newRows[idx] = { ...newRows[idx], [field]: value };
    setInputCounts(newRows);
  };

  const handleQuickAddTerm = (term: string) => {
    const lastRow = inputCounts[inputCounts.length - 1];
    if (!lastRow.term && !lastRow.count) {
      handleInputChange(inputCounts.length - 1, 'term', term);
    } else {
      setInputCounts([...inputCounts, { term, count: '' }]);
    }
  };

  const runAnalysis = () => {
    if (!masterResult) {
      alert("請先載入產品或產生主檔");
      return;
    }
    const val = parseFloat(exposureVal);
    if (isNaN(val) || val <= 0) {
      alert("請輸入有效的暴露量數值");
      return;
    }

    // Filter valid rows: Must have a term name. Count defaults to 0 if empty.
    const validCounts = inputCounts
      .filter(r => r.term.trim() !== '') 
      .map(r => ({
        term: r.term,
        count: parseInt(r.count, 10) || 0
      }));

    // Allow analysis even if validCounts is empty (Report will show 0 cases)
    const report = performAnalysis(masterResult, {
      quarter,
      exposure_value: val,
      exposure_unit: exposureUnit,
      ae_counts: validCounts
    }, {
      includeAllMasterTerms: showAllTerms
    });

    setAnalysisReport(report);
    setMonitorSaveStatus('idle');
  };

  const handleSaveAnalysis = () => {
    if (!analysisReport || !selectedProductId) {
      alert("需選擇產品並執行分析後才能儲存");
      return;
    }

    const records: QuarterlyAeMonitor[] = [];
    const now = new Date().toISOString();

    analysisReport.rows.forEach(row => {
      let status: 'normal' | 'yellow' | 'red' = 'normal';
      if (row.status === 'alert') status = 'red';
      if (row.status === 'warning') status = 'yellow';
      if (row.status === 'unexpected') status = 'red'; // Unexpected is also a RED flag in DB

      // Simple random ID generation
      const id = Date.now().toString(36) + Math.random().toString(36).substring(2);

      records.push({
        id,
        product_id: selectedProductId,
        quarter: quarter,
        exposure_value: parseFloat(exposureVal),
        exposure_unit: exposureUnit,
        ae_term: row.ae_term,
        count: row.count,
        rate_pct: row.incidence_rate_pct,
        threshold_pct: row.threshold_pct,
        status: status,
        generated_at: now
      });
    });

    if (analysisReport.rows.length > 0) {
       db.saveQuarterlyAeMonitors(records);
       setDbUpdateTrigger(prev => prev + 1); // Force library update
    }

    setMonitorSaveStatus('saved');
  };

  const handleDeleteProduct = (pid: string) => {
    if(confirm('確定要刪除此產品及其所有相關資料嗎？')) {
      db.deleteProduct(pid);
      setSavedProducts(db.getProducts());
      if (currentExtractionProductId === pid) {
        setCurrentExtractionProductId(null);
      }
    }
  };

  const handleDeleteMonitorRecord = (id?: string) => {
    if (!id) return;
    if (confirm('確定要刪除這筆監測紀錄嗎？')) {
      db.deleteMonitorRecord(id);
      setDbUpdateTrigger(prev => prev + 1); // Refresh list
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-800 font-sans">
      {/* Top Navigation */}
      <nav className="bg-slate-900 text-white shadow-md sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-brand-500 p-2 rounded text-white">
              <Activity size={20} />
            </div>
            <span className="font-bold text-lg tracking-tight">PV 智慧監測平台</span>
          </div>
          <div className="flex gap-1 bg-slate-800 p-1 rounded-lg">
            <button
              onClick={() => setActiveMode('generator')}
              className={`px-3 py-2 text-sm font-medium rounded-md transition-all flex items-center gap-2 ${
                activeMode === 'generator' ? 'bg-brand-600 text-white shadow' : 'text-slate-400 hover:text-white'
              }`}
            >
              <FileText size={16}/>
              1. AE 主檔生成
            </button>
            <button
              onClick={() => setActiveMode('monitor')}
              className={`px-3 py-2 text-sm font-medium rounded-md transition-all flex items-center gap-2 ${
                activeMode === 'monitor' ? 'bg-brand-600 text-white shadow' : 'text-slate-400 hover:text-white'
              }`}
            >
              <Activity size={16}/>
              2. 訊號監測
            </button>
            <button
              onClick={() => setActiveMode('library')}
              className={`px-3 py-2 text-sm font-medium rounded-md transition-all flex items-center gap-2 ${
                activeMode === 'library' ? 'bg-brand-600 text-white shadow' : 'text-slate-400 hover:text-white'
              }`}
            >
              <Database size={16}/>
              資料庫管理
            </button>
          </div>
        </div>
      </nav>

      <div className="max-w-6xl mx-auto p-4 md:p-8">

        {/* --- MODE 1: GENERATOR --- */}
        {activeMode === 'generator' && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 space-y-6">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
              <div className="flex items-center gap-3 mb-6">
                <div className="w-10 h-10 rounded-full bg-brand-100 flex items-center justify-center text-brand-600">
                  <FileText size={20} />
                </div>
                <div>
                  <h2 className="font-bold text-lg text-slate-900">仿單資料提取</h2>
                  <p className="text-slate-500 text-sm">上傳仿單 PDF、圖片或貼上文字，自動轉換為標準 JSON 主檔</p>
                </div>
              </div>

              <div className="grid lg:grid-cols-2 gap-8">
                {/* Input Area */}
                <div className="space-y-4">
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-2">仿單文字 (Text)</label>
                    <textarea
                      value={textInput}
                      onChange={(e) => setTextInput(e.target.value)}
                      className="w-full h-32 p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none text-sm"
                      placeholder="貼上仿單內容..."
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-2">仿單檔案 (PDF / 圖片)</label>
                    <div className="border-2 border-dashed border-slate-300 rounded-lg p-4 hover:bg-slate-50 text-center cursor-pointer relative transition-colors bg-slate-50/50">
                      <input 
                        type="file" 
                        accept="image/*,application/pdf" 
                        onChange={handleFileChange} 
                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" 
                      />
                      {uploadedFile ? (
                        <div className="relative flex flex-col items-center justify-center p-2">
                           {uploadedFile.type === 'application/pdf' ? (
                             <div className="flex flex-col items-center text-brand-600">
                               <FileType size={48} className="mb-2" />
                               <span className="text-sm font-medium text-slate-700 max-w-[200px] truncate">{uploadedFile.name}</span>
                               <span className="text-xs text-slate-400 uppercase">PDF Document</span>
                             </div>
                           ) : (
                             fileDataUrl && (
                               <>
                                <img src={fileDataUrl} alt="Preview" className="max-h-48 rounded shadow-sm border border-slate-200" />
                                <span className="text-xs text-slate-400 mt-2 max-w-[200px] truncate">{uploadedFile.name}</span>
                               </>
                             )
                           )}
                           <button 
                             onClick={handleClearFile} 
                             className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1.5 shadow-md hover:bg-red-600 z-10"
                             title="移除檔案"
                           >
                             <Trash2 size={14} />
                           </button>
                        </div>
                      ) : (
                        <div className="text-slate-400 py-6">
                          <Upload size={32} className="mx-auto mb-2 text-slate-300" />
                          <p className="text-sm font-medium text-slate-600">點擊上傳 PDF 或 圖片</p>
                          <p className="text-xs text-slate-400 mt-1">支援 .pdf, .jpg, .png</p>
                        </div>
                      )}
                    </div>
                  </div>
                  <button
                    onClick={handleProcess}
                    disabled={loading}
                    className="w-full py-3 bg-brand-600 hover:bg-brand-700 text-white rounded-lg font-medium shadow-lg shadow-brand-200 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                  >
                    {loading ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : <Database size={18} />}
                    {loading ? 'AI 解析中...' : '產生 AE Master'}
                  </button>
                  {error && <div className="p-3 bg-red-50 text-red-600 rounded-lg text-sm flex items-center gap-2"><AlertCircle size={16}/>{error}</div>}
                </div>

                {/* Result Area - Now Editable */}
                <div className="flex flex-col h-full bg-slate-50 rounded-lg border border-slate-200 overflow-hidden min-h-[400px]">
                  <div className="flex justify-between items-center px-4 py-2 border-b border-slate-200 bg-white">
                    <span className="font-semibold text-sm">解析結果 (可編輯)</span>
                    <div className="flex gap-2">
                       {masterResult && (
                         <button 
                           onClick={handleSaveToDb}
                           disabled={saveStatus === 'saved'}
                           className={`px-3 py-1 text-xs rounded font-medium flex items-center gap-1 transition-colors ${saveStatus === 'saved' ? 'bg-green-100 text-green-700' : 'bg-brand-600 text-white hover:bg-brand-700'}`}
                         >
                           {saveStatus === 'saved' ? <Check size={14}/> : <Save size={14}/>}
                           {saveStatus === 'saved' ? '已儲存' : (currentExtractionProductId ? '儲存更新' : '存入資料庫')}
                         </button>
                       )}
                    </div>
                  </div>
                  <div className="flex-1 overflow-auto p-4 relative">
                    {!masterResult ? (
                      <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-300">
                        <Database size={40} className="mb-2 opacity-20" />
                        <p className="text-sm">尚無資料</p>
                      </div>
                    ) : (
                      <div className="space-y-4">
                        <div className="grid grid-cols-2 gap-2 text-xs bg-white p-3 rounded border border-slate-200">
                           <div className="flex items-center gap-2">
                             <span className="text-slate-400 whitespace-nowrap">Product:</span>
                             <input 
                               value={masterResult.product_name || ''} 
                               onChange={(e) => setMasterResult({...masterResult, product_name: e.target.value})}
                               className="w-full text-xs border-b border-slate-200 focus:border-brand-500 outline-none"
                             />
                           </div>
                           <div className="flex items-center gap-2">
                             <span className="text-slate-400 whitespace-nowrap">Ver:</span>
                             <input 
                               value={masterResult.label_version_date || ''} 
                               onChange={(e) => setMasterResult({...masterResult, label_version_date: e.target.value})}
                               className="w-full text-xs border-b border-slate-200 focus:border-brand-500 outline-none"
                             />
                           </div>
                        </div>

                        {/* List Header */}
                        <div className="grid grid-cols-12 gap-2 px-2 text-xs font-semibold text-slate-500">
                           <div className="col-span-3">SOC / Freq</div>
                           <div className="col-span-6">AE Terms (以逗號分隔)</div>
                           <div className="col-span-2 text-right">門檻%</div>
                           <div className="col-span-1"></div>
                        </div>

                        <div className="space-y-2">
                           {masterResult.ae_master?.map((item: any, idx: number) => (
                             <div key={idx} className="bg-white p-3 rounded border border-slate-200 hover:border-brand-300 transition-colors group">
                               <div className="grid grid-cols-12 gap-3 items-start">
                                 {/* Column 1: SOC & Frequency */}
                                 <div className="col-span-3 space-y-2">
                                    <input 
                                      value={item.soc} 
                                      onChange={(e) => handleResultChange(idx, 'soc', e.target.value)}
                                      placeholder="SOC"
                                      className="w-full text-xs px-2 py-1 border border-slate-200 rounded focus:ring-1 focus:ring-brand-500 outline-none"
                                    />
                                    <input 
                                      value={item.label_frequency_text} 
                                      onChange={(e) => handleResultChange(idx, 'label_frequency_text', e.target.value)}
                                      placeholder="常見/罕見..."
                                      className="w-full text-xs px-2 py-1 border border-slate-200 rounded focus:ring-1 focus:ring-brand-500 outline-none"
                                    />
                                 </div>

                                 {/* Column 2: Terms (Joined) */}
                                 <div className="col-span-6">
                                    <textarea 
                                      value={item.ae_terms_split.join(', ')} 
                                      onChange={(e) => handleResultChange(idx, 'ae_terms_split', e.target.value)}
                                      placeholder="AE1, AE2..."
                                      rows={3}
                                      className="w-full text-sm px-2 py-1 border border-slate-200 rounded focus:ring-1 focus:ring-brand-500 outline-none resize-none"
                                    />
                                 </div>

                                 {/* Column 3: Threshold & Action */}
                                 <div className="col-span-3 flex flex-col items-end gap-2">
                                    <div className="flex items-center gap-1 w-full">
                                      <input 
                                        type="number"
                                        step="0.01" 
                                        value={item.label_threshold_upper_pct} 
                                        onChange={(e) => handleResultChange(idx, 'label_threshold_upper_pct', parseFloat(e.target.value))}
                                        className="w-full text-right text-sm font-mono font-bold text-brand-600 px-2 py-1 border border-slate-200 rounded focus:ring-1 focus:ring-brand-500 outline-none"
                                      />
                                      <span className="text-xs text-slate-400">%</span>
                                    </div>
                                    <button 
                                      onClick={() => handleDeleteResultItem(idx)}
                                      className="text-slate-300 hover:text-red-500 transition-colors p-1"
                                      title="刪除此列"
                                    >
                                      <Trash2 size={16} />
                                    </button>
                                 </div>
                               </div>
                             </div>
                           ))}
                        </div>

                        <button 
                          onClick={handleAddResultItem}
                          className="w-full py-2 border-2 border-dashed border-slate-300 rounded text-slate-500 text-xs font-medium hover:border-brand-400 hover:text-brand-600 hover:bg-brand-50 transition-all flex items-center justify-center gap-1"
                        >
                          <Plus size={14} /> 新增提取項目
                        </button>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* --- MODE 2: MONITORING --- */}
        {activeMode === 'monitor' && (
          <div className="animate-in fade-in slide-in-from-right-4 duration-500 space-y-6">

            {/* Toolbar */}
            <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-wrap gap-4 items-center justify-between">
               <div className="flex items-center gap-2 w-full md:w-auto">
                 <label className="text-sm font-semibold text-slate-700">選擇產品主檔：</label>
                 <select 
                   value={selectedProductId} 
                   onChange={handleLoadProduct}
                   className="flex-1 md:w-64 px-3 py-2 border border-slate-300 rounded text-sm focus:ring-2 focus:ring-brand-500 outline-none"
                 >
                   <option value="">-- 請選擇產品 --</option>
                   {savedProducts.map(p => (
                     <option key={p.product_id} value={p.product_id}>{p.product_name} ({p.label_version_date})</option>
                   ))}
                 </select>
               </div>

               {!selectedProductId && !masterResult && (
                 <button onClick={() => setActiveMode('generator')} className="text-sm text-brand-600 underline">沒有產品？前往新增</button>
               )}
            </div>

            {/* Input Form */}
            <div className="grid lg:grid-cols-3 gap-6">
              <div className="lg:col-span-1 space-y-6">
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                  <h3 className="font-bold text-slate-900 mb-4 flex items-center gap-2">
                    <Activity size={18} className="text-brand-600" />
                    本季暴露量設定
                  </h3>
                  <div className="space-y-4">
                    <div>
                      <label className="block text-xs font-semibold text-slate-500 mb-1 uppercase">季度名稱</label>
                      <input type="text" value={quarter} onChange={e => setQuarter(e.target.value)} className="w-full px-3 py-2 border border-slate-300 rounded focus:ring-2 focus:ring-brand-500 outline-none text-sm" placeholder="2025Q1" />
                    </div>
                    <div>
                      <label className="block text-xs font-semibold text-slate-500 mb-1 uppercase">暴露量數值 (分母)</label>
                      <input type="number" value={exposureVal} onChange={e => setExposureVal(e.target.value)} className="w-full px-3 py-2 border border-slate-300 rounded focus:ring-2 focus:ring-brand-500 outline-none text-sm font-mono" placeholder="1000" />
                    </div>
                    <div>
                      <label className="block text-xs font-semibold text-slate-500 mb-1 uppercase">暴露量單位</label>
                      <select 
                        value={exposureUnit} 
                        onChange={e => setExposureUnit(e.target.value)} 
                        className="w-full px-3 py-2 border border-slate-300 rounded focus:ring-2 focus:ring-brand-500 outline-none text-sm bg-white"
                      >
                        <option value="日">日</option>
                        <option value="月">月</option>
                        <option value="季">季</option>
                        <option value="年">年</option>
                      </select>
                    </div>
                  </div>
                </div>

                {masterResult && (
                  <div className="bg-slate-50 rounded-xl border border-slate-200 p-4 max-h-[400px] overflow-hidden flex flex-col">
                    <h4 className="font-semibold text-xs text-slate-500 uppercase mb-3">主檔可用 AE Term 參考</h4>
                    <div className="flex-1 overflow-y-auto space-y-1 pr-2">
                      {masterResult.ae_master.map((item: any, i: number) => (
                         <button 
                          key={i} 
                          onClick={() => handleQuickAddTerm(item.ae_terms_split[0])}
                          className="text-left w-full text-xs px-2 py-1.5 bg-white border border-slate-200 rounded hover:border-brand-400 hover:text-brand-700 truncate transition-colors"
                          title={item.ae_terms_split.join(', ')}
                         >
                           + {item.ae_terms_split.join(' / ')}
                         </button>
                      ))}
                    </div>
                  </div>
                )}
              </div>

              <div className="lg:col-span-2 space-y-6">
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                  <div className="flex justify-between items-center mb-4">
                     <h3 className="font-bold text-slate-900 flex items-center gap-2">
                       <BarChart3 size={18} className="text-brand-600" />
                       AE 案例數輸入
                     </h3>
                     <button onClick={handleAddRow} className="text-xs flex items-center gap-1 bg-brand-50 text-brand-700 px-3 py-1.5 rounded hover:bg-brand-100 transition-colors font-medium">
                       <Plus size={14} /> 新增列
                     </button>
                  </div>

                  <div className="space-y-2 max-h-[400px] overflow-y-auto pr-2">
                    {inputCounts.map((row, idx) => (
                      <div key={idx} className="flex gap-3 items-center">
                        <div className="flex-1">
                          <input 
                            type="text" 
                            value={row.term} 
                            onChange={(e) => handleInputChange(idx, 'term', e.target.value)}
                            placeholder="輸入 AE Term (建議點選左側參考清單)"
                            className="w-full px-3 py-2 border border-slate-300 rounded text-sm focus:ring-1 focus:ring-brand-500 outline-none"
                          />
                        </div>
                        <div className="w-24">
                          <input 
                            type="number" 
                            min="0"
                            value={row.count} 
                            onChange={(e) => handleInputChange(idx, 'count', e.target.value)}
                            placeholder="Count"
                            className="w-full px-3 py-2 border border-slate-300 rounded text-sm text-center focus:ring-1 focus:ring-brand-500 outline-none"
                          />
                        </div>
                        <button onClick={() => handleRemoveRow(idx)} className="text-slate-400 hover:text-red-500 transition-colors p-1">
                          <Trash2 size={16} />
                        </button>
                      </div>
                    ))}
                    {inputCounts.length === 0 && <div className="text-center text-slate-400 text-sm py-4">請新增案例輸入</div>}
                  </div>

                  <div className="mt-6 pt-4 border-t border-slate-100 flex justify-end">
                    <button 
                      onClick={runAnalysis}
                      disabled={!masterResult}
                      className="px-6 py-2.5 bg-brand-600 hover:bg-brand-700 text-white font-medium rounded-lg shadow-lg shadow-brand-200 transition-all flex items-center gap-2 disabled:opacity-50"
                    >
                      <Activity size={18} />
                      執行訊號分析
                    </button>
                  </div>
                </div>

                {analysisReport && (
                   <div className="bg-white rounded-xl shadow-lg border border-slate-200 overflow-hidden animate-in fade-in slide-in-from-bottom-8">
                     <div className="px-6 py-4 bg-slate-900 text-white flex justify-between items-center">
                       <div className="flex items-center gap-4">
                         <h3 className="font-bold text-lg">分析報表 ({quarter})</h3>
                         <div className="flex items-center bg-slate-800 rounded-lg p-1 border border-slate-700">
                            <button
                              onClick={() => setShowAllTerms(!showAllTerms)}
                              className={`flex items-center gap-2 px-3 py-1 text-xs font-medium rounded transition-all ${
                                showAllTerms ? 'bg-brand-500 text-white' : 'text-slate-400 hover:text-white'
                              }`}
                            >
                              {showAllTerms ? <ToggleRight size={16} /> : <ToggleLeft size={16} />}
                              顯示所有主檔項目
                            </button>
                         </div>
                       </div>

                       <div className="flex items-center gap-4">
                         <div className="text-xs text-slate-400">
                           Exposure: {exposureVal} {exposureUnit}
                         </div>
                         {selectedProductId && (
                           <button 
                             onClick={handleSaveAnalysis}
                             disabled={monitorSaveStatus === 'saved'}
                             className={`text-xs px-3 py-1.5 rounded font-medium flex items-center gap-1 transition-colors ${monitorSaveStatus === 'saved' ? 'bg-green-500 text-white' : 'bg-white text-slate-900 hover:bg-slate-100'}`}
                           >
                             {monitorSaveStatus === 'saved' ? <Check size={14}/> : <Save size={14}/>}
                             {monitorSaveStatus === 'saved' ? '已存入' : '儲存報表'}
                           </button>
                         )}
                       </div>
                     </div>

                     <div className="p-6">
                       {/* Summary Cards */}
                       <div className="grid grid-cols-4 gap-4 mb-6">
                         <div className="bg-rose-100 border border-rose-200 p-4 rounded-lg">
                           <div className="text-rose-700 text-xs font-bold uppercase mb-1 flex items-center gap-1">
                             <AlertTriangle size={14} /> 未預期 AE
                           </div>
                           <div className="text-2xl font-bold text-rose-900">{analysisReport.unexpected.length}</div>
                         </div>
                         <div className="bg-red-50 border border-red-100 p-4 rounded-lg">
                           <div className="text-red-600 text-xs font-bold uppercase mb-1">⚠️ 發生率異常</div>
                           <div className="text-2xl font-bold text-slate-900">{analysisReport.alerts.length}</div>
                         </div>
                         <div className="bg-yellow-50 border border-yellow-100 p-4 rounded-lg">
                           <div className="text-yellow-600 text-xs font-bold uppercase mb-1">⚠️ 關注提醒</div>
                           <div className="text-2xl font-bold text-slate-900">{analysisReport.rows.filter(r => r.status === 'warning').length}</div>
                         </div>
                         <div className="bg-slate-50 border border-slate-200 p-4 rounded-lg">
                           <div className="text-slate-500 text-xs font-bold uppercase mb-1">正常 / 無訊號</div>
                           <div className="text-2xl font-bold text-slate-900">{analysisReport.rows.filter(r => r.status === 'normal').length}</div>
                         </div>
                       </div>

                       {/* Table */}
                       <div className="overflow-x-auto border rounded-lg border-slate-200 max-h-[600px]">
                         <table className="w-full text-sm text-left relative">
                           <thead className="bg-slate-50 text-slate-600 font-semibold border-b border-slate-200 sticky top-0 z-10 shadow-sm">
                             <tr>
                               <th className="px-4 py-3">判定</th>
                               <th className="px-4 py-3">AE Term</th>
                               <th className="px-4 py-3">SOC / 仿單頻率</th>
                               <th className="px-4 py-3 text-right">本季 Count</th>
                               <th className="px-4 py-3 text-right">本季 Rate (%)</th>
                               <th className="px-4 py-3 text-right">仿單門檻 (%)</th>
                             </tr>
                           </thead>
                           <tbody className="divide-y divide-slate-100">
                             {analysisReport.rows.length === 0 ? (
                               <tr><td colSpan={6} className="px-4 py-4 text-center text-slate-400">本季無不良反應案例</td></tr>
                             ) : analysisReport.rows.map((row, idx) => (
                               <tr key={idx} className={
                                 row.status === 'unexpected' ? 'bg-rose-50' :
                                 row.status === 'alert' ? 'bg-red-50' : 
                                 row.status === 'warning' ? 'bg-yellow-50' : 
                                 'hover:bg-slate-50'
                               }>
                                 <td className="px-4 py-3">
                                   {row.status === 'unexpected' && <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded text-xs font-bold bg-rose-600 text-white shadow-sm"><AlertTriangle size={12}/> 未預期 (Unexpected)</span>}
                                   {row.status === 'alert' && <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded text-xs font-bold bg-red-200 text-red-800">⚠️ 異常</span>}
                                   {row.status === 'warning' && <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded text-xs font-bold bg-yellow-200 text-yellow-800">⚠️ 提醒</span>}
                                   {row.status === 'normal' && <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded text-xs font-medium bg-green-100 text-green-800">正常</span>}
                                 </td>
                                 <td className="px-4 py-3 font-medium text-slate-900">{row.ae_term}</td>
                                 <td className="px-4 py-3 text-slate-500 text-xs">
                                   {row.status === 'unexpected' ? (
                                     <span className="text-rose-600 italic">未登載於主檔</span>
                                   ) : (
                                     <>
                                       <div className="truncate max-w-[150px]" title={row.soc}>{row.soc}</div>
                                       <div>{row.frequency_category}</div>
                                     </>
                                   )}
                                 </td>
                                 <td className="px-4 py-3 text-right font-mono">{row.count}</td>
                                 <td className={`px-4 py-3 text-right font-mono font-bold ${
                                   row.status === 'unexpected' ? 'text-rose-700' :
                                   row.status === 'alert' ? 'text-red-600' : 
                                   'text-slate-700'
                                 }`}>
                                   {row.incidence_rate_pct.toFixed(4)}%
                                 </td>
                                 <td className="px-4 py-3 text-right font-mono text-slate-500">
                                   {row.threshold_pct > 0 ? `${row.threshold_pct}%` : '-'}
                                 </td>
                               </tr>
                             ))}
                           </tbody>
                         </table>
                       </div>
                     </div>
                   </div>
                )}
              </div>
            </div>
          </div>
        )}

        {/* --- MODE 3: LIBRARY --- */}
        {activeMode === 'library' && (
           <div className="animate-in fade-in slide-in-from-right-4 duration-500 space-y-6">
             <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                <div className="flex items-center gap-3 mb-6">
                  <div className="bg-brand-100 p-2 rounded-full text-brand-600">
                    <Database size={24} />
                  </div>
                  <h2 className="text-xl font-bold text-slate-900">資料庫檢視</h2>
                </div>

                <div className="space-y-8">
                  {/* Products Section */}
                  <section>
                    <h3 className="font-bold text-slate-800 mb-3 flex items-center gap-2">
                      <FolderOpen size={18} />
                      產品主檔清單 (products)
                    </h3>
                    <div className="overflow-x-auto border rounded-lg border-slate-200">
                      <table className="w-full text-sm text-left">
                        <thead className="bg-slate-50 text-slate-600 font-semibold">
                          <tr>
                            <th className="px-4 py-2">Product Name</th>
                            <th className="px-4 py-2">Version Date</th>
                            <th className="px-4 py-2">ID</th>
                            <th className="px-4 py-2 text-right">Actions</th>
                          </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                          {savedProducts.map(p => (
                            <tr key={p.product_id} className="hover:bg-slate-50">
                              <td className="px-4 py-2 font-medium">{p.product_name}</td>
                              <td className="px-4 py-2 text-slate-500">{p.label_version_date}</td>
                              <td className="px-4 py-2 text-xs font-mono text-slate-400">{p.product_id}</td>
                              <td className="px-4 py-2 text-right">
                                <button onClick={() => handleDeleteProduct(p.product_id)} className="text-red-500 hover:bg-red-50 p-1 rounded">
                                  <Trash2 size={14} />
                                </button>
                              </td>
                            </tr>
                          ))}
                          {savedProducts.length === 0 && (
                             <tr><td colSpan={4} className="px-4 py-4 text-center text-slate-400">尚無產品資料</td></tr>
                          )}
                        </tbody>
                      </table>
                    </div>
                  </section>

                  {/* Sample Raw Data Section - Just visualizing the last 5 records of monitor for demo */}
                  <section>
                    <h3 className="font-bold text-slate-800 mb-3 flex items-center gap-2">
                      <History size={18} />
                      最新監測紀錄 (quarterly_ae_monitor)
                    </h3>
                    <div className="overflow-x-auto border rounded-lg border-slate-200">
                      <table className="w-full text-sm text-left">
                        <thead className="bg-slate-50 text-slate-600 font-semibold">
                          <tr>
                            <th className="px-4 py-2">Time</th>
                            <th className="px-4 py-2">Product Name</th>
                            <th className="px-4 py-2">Qtr</th>
                            <th className="px-4 py-2">AE Term (Rate%)</th>
                            <th className="px-4 py-2">Count</th>
                            <th className="px-4 py-2">Status</th>
                            <th className="px-4 py-2 text-right">Action</th>
                          </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                          {db.getQuarterlyAeMonitors().slice().reverse().map((m, i) => {
                            const product = savedProducts.find(p => p.product_id === m.product_id);
                            return (
                              <tr key={m.id || i} className="hover:bg-slate-50">
                                <td className="px-4 py-2 text-xs text-slate-500">{new Date(m.generated_at).toLocaleDateString()}</td>
                                <td className="px-4 py-2 text-xs font-medium text-slate-700">{product ? product.product_name : m.product_id}</td>
                                <td className="px-4 py-2">{m.quarter}</td>
                                <td className="px-4 py-2">
                                  <span className="font-medium">{m.ae_term}</span>
                                  <span className="text-xs text-slate-500 ml-1">({m.rate_pct.toFixed(2)}%)</span>
                                </td>
                                <td className="px-4 py-2 font-mono">{m.count}</td>
                                <td className="px-4 py-2">
                                  <span className={`text-xs px-2 py-0.5 rounded font-bold ${
                                    m.status === 'red' ? 'bg-red-100 text-red-700' :
                                    m.status === 'yellow' ? 'bg-yellow-100 text-yellow-700' :
                                    'bg-green-100 text-green-700'
                                  }`}>
                                    {m.status.toUpperCase()}
                                  </span>
                                </td>
                                <td className="px-4 py-2 text-right">
                                  {m.id && (
                                    <button 
                                      onClick={() => handleDeleteMonitorRecord(m.id)}
                                      className="text-slate-400 hover:text-red-500 p-1 rounded hover:bg-red-50 transition-colors"
                                      title="刪除此紀錄"
                                    >
                                      <Trash2 size={14} />
                                    </button>
                                  )}
                                </td>
                              </tr>
                            );
                          })}
                          {db.getQuarterlyAeMonitors().length === 0 && (
                             <tr><td colSpan={7} className="px-4 py-4 text-center text-slate-400">尚無監測紀錄</td></tr>
                          )}
                        </tbody>
                      </table>
                    </div>
                  </section>
                </div>
             </div>
           </div>
        )}

      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { extractAEMaster, FileInput } from './services/gemini';
import { performAnalysis, AnalysisReport } from './services/analysis';
import { db, Product, LabelAeMaster, QuarterlyAeMonitor } from './services/db';
import { Clipboard, Upload, FileText, Activity, AlertCircle, Check, Database, BarChart3, Plus, Trash2, ArrowRight, Save, FolderOpen, Table, History, ToggleLeft, ToggleRight, FileType, AlertTriangle, X, Edit2 } from 'lucide-react';

export default function App() {
  // Navigation State
  const [activeMode, setActiveMode] = useState<'generator' | 'monitor' | 'library'>('generator');

  // Generator State
  const [textInput, setTextInput] = useState('');
  const [uploadedFile, setUploadedFile] = useState<File | null>(null);
  const [fileDataUrl, setFileDataUrl] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [masterResult, setMasterResult] = useState<any>(null); // The JSON from Gemini
  const [currentExtractionProductId, setCurrentExtractionProductId] = useState<string | null>(null); // Tracks the ID if saved
  const [error, setError] = useState<string | null>(null);
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved'>('idle');

  // Monitoring State
  const [quarter, setQuarter] = useState('2025Q1');
  const [exposureVal, setExposureVal] = useState<string>('');
  const [exposureUnit, setExposureUnit] = useState('年');
  const [inputCounts, setInputCounts] = useState<{term: string, count: string}[]>([{term: '', count: ''}]);
  const [analysisReport, setAnalysisReport] = useState<AnalysisReport | null>(null);
  const [showAllTerms, setShowAllTerms] = useState(false);

  // Database Integration State
  const [savedProducts, setSavedProducts] = useState<Product[]>([]);
  const [selectedProductId, setSelectedProductId] = useState<string>('');
  const [monitorSaveStatus, setMonitorSaveStatus] = useState<'idle' | 'saved'>('idle');
  // Trigger to force re-render of library view when DB changes
  const [dbUpdateTrigger, setDbUpdateTrigger] = useState(0);

  // Refresh products list
  useEffect(() => {
    setSavedProducts(db.getProducts());
  }, [activeMode, dbUpdateTrigger]);

  // Effect to re-run analysis when showAllTerms toggles
  useEffect(() => {
    if (analysisReport && masterResult) {
      runAnalysis();
    }
  }, [showAllTerms]);

  // --- Handlers for Generator ---
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setUploadedFile(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setFileDataUrl(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleClearFile = (e: React.MouseEvent) => {
    e.preventDefault();
    setUploadedFile(null);
    setFileDataUrl(null);
  };

  const handleProcess = async () => {
    if (!textInput && !uploadedFile) {
      setError("請提供文字描述或上傳檔案");
      return;
    }

    setLoading(true);
    setError(null);
    setMasterResult(null);
    setCurrentExtractionProductId(null); // Reset ID for new extraction
    setSaveStatus('idle');

    try {
      let fileInput: FileInput | undefined = undefined;
      if (uploadedFile && fileDataUrl) {
        // extract base64 from dataUrl (remove "data:xxxx;base64,")
        const base64 = fileDataUrl.split(',')[1];
        fileInput = {
          data: base64,
          mimeType: uploadedFile.type
        };
      }

      const data = await extractAEMaster(textInput, fileInput);
      setMasterResult(data);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "發生錯誤，請檢查 API Key 或重試。");
    } finally {
      setLoading(false);
    }
  };

  // --- Master Result Editing Handlers ---

  const handleResultChange = (index: number, field: string, value: any) => {
    if (!masterResult) return;
    const newAeMaster = [...masterResult.ae_master];

    if (field === 'ae_terms_split') {
      // Input comes as string, split by comma for storage
      newAeMaster[index] = {
        ...newAeMaster[index],
        ae_terms_split: value.split(/[,，、;]+/).map((t: string) => t.trim()).filter((t: string) => t)
      };
    } else {
      newAeMaster[index] = { ...newAeMaster[index], [field]: value };
    }

    setMasterResult({ ...masterResult, ae_master: newAeMaster });
    setSaveStatus('idle'); // Reset save status if modified
  };

  const handleDeleteResultItem = (index: number) => {
    if (!masterResult) return;
    const newAeMaster = masterResult.ae_master.filter((_: any, i: number) => i !== index);
    setMasterResult({ ...masterResult, ae_master: newAeMaster });
    setSaveStatus('idle');
  };

  const handleAddResultItem = () => {
    if (!masterResult) return;
    const newItem = {
      soc: "",
      ae_term_raw: "",
      ae_terms_split: [],
      label_frequency_text: "",
      label_threshold_upper_pct: 0,
      mapping_rule_note: "Manual Entry"
    };
    setMasterResult({ 
      ...masterResult, 
      ae_master: [...(masterResult.ae_master || []), newItem] 
    });
    setSaveStatus('idle');
  };

  const handleSaveToDb = () => {
    if (!masterResult) return;
    try {
      // If we already saved this session, update the existing ID. Otherwise undefined (create new).
      const newId = db.saveExtractedMaster(masterResult, currentExtractionProductId || undefined);

      setCurrentExtractionProductId(newId);
      setSaveStatus('saved');
      setSavedProducts(db.getProducts());

      // Auto select this new product if user goes to monitor tab
      setSelectedProductId(newId);
    } catch (e) {
      console.error(e);
      alert("儲存失敗");
    }
  };

  // --- Handlers for Monitoring ---
  const handleLoadProduct = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const pid = e.target.value;
    setSelectedProductId(pid);
    if (pid) {
      const analysisFormat = db.getMasterForAnalysis(pid);
      setMasterResult(analysisFormat);
      setAnalysisReport(null); // Clear previous report
      setMonitorSaveStatus('idle');
    } else {
      setMasterResult(null);
    }
  };

  const handleAddRow = () => {
    setInputCounts([...inputCounts, { term: '', count: '' }]);
  };

  const handleRemoveRow = (idx: number) => {
    setInputCounts(inputCounts.filter((_, i) => i !== idx));
  };

  const handleInputChange = (idx: number, field: 'term' | 'count', value: string) => {
    const newRows = [...inputCounts];
    newRows[idx] = { ...newRows[idx], [field]: value };
    setInputCounts(newRows);
  };

  const handleQuickAddTerm = (term: string) => {
    const lastRow = inputCounts[inputCounts.length - 1];
    if (!lastRow.term && !lastRow.count) {
      handleInputChange(inputCounts.length - 1, 'term', term);
    } else {
      setInputCounts([...inputCounts, { term, count: '' }]);
    }
  };

  const runAnalysis = () => {
    if (!masterResult) {
      alert("請先載入產品或產生主檔");
      return;
    }
    const val = parseFloat(exposureVal);

    // VALIDATION ALERT
    if (!exposureVal || isNaN(val) || val <= 0) {
      alert("⚠️ 注意：尚未填入暴露量！\n\n請在「本季暴露量設定」欄位中填入有效的數值 (分母)，才能進行發生率計算。");
      return;
    }

    // Filter valid rows: Must have a term name. Count defaults to 0 if empty.
    const validCounts = inputCounts
      .filter(r => r.term.trim() !== '') 
      .map(r => ({
        term: r.term,
        count: parseInt(r.count, 10) || 0
      }));

    // Allow analysis even if validCounts is empty (Report will show 0 cases)
    const report = performAnalysis(masterResult, {
      quarter,
      exposure_value: val,
      exposure_unit: exposureUnit,
      ae_counts: validCounts
    }, {
      includeAllMasterTerms: showAllTerms
    });

    setAnalysisReport(report);
    setMonitorSaveStatus('idle');
  };

  const handleSaveAnalysis = () => {
    if (!analysisReport || !selectedProductId) {
      alert("需選擇產品並執行分析後才能儲存");
      return;
    }

    const records: QuarterlyAeMonitor[] = [];
    const now = new Date().toISOString();

    if (analysisReport.rows.length === 0) {
      // HANDLE EMPTY REPORT: Save a single record indicating No AEs
      const id = Date.now().toString(36) + Math.random().toString(36).substring(2);
      records.push({
        id,
        product_id: selectedProductId,
        quarter: quarter,
        exposure_value: parseFloat(exposureVal),
        exposure_unit: exposureUnit,
        ae_term: "本季無不良反應 (No Adverse Events)",
        count: 0,
        rate_pct: 0,
        threshold_pct: 0,
        status: 'normal',
        generated_at: now
      });
    } else {
      // Handle normal report with rows
      analysisReport.rows.forEach(row => {
        let status: 'normal' | 'yellow' | 'red' = 'normal';
        if (row.status === 'alert') status = 'red';
        if (row.status === 'warning') status = 'yellow';
        if (row.status === 'unexpected') status = 'red'; // Unexpected is also a RED flag in DB

        // Simple random ID generation
        const id = Date.now().toString(36) + Math.random().toString(36).substring(2);

        records.push({
          id,
          product_id: selectedProductId,
          quarter: quarter,
          exposure_value: parseFloat(exposureVal),
          exposure_unit: exposureUnit,
          ae_term: row.ae_term,
          count: row.count,
          rate_pct: row.incidence_rate_pct,
          threshold_pct: row.threshold_pct,
          status: status,
          generated_at: now
        });
      });
    }

    if (records.length > 0) {
       db.saveQuarterlyAeMonitors(records);
       setDbUpdateTrigger(prev => prev + 1); // Force library update
    }

    setMonitorSaveStatus('saved');
  };

  const handleDeleteProduct = (pid: string) => {
    if(confirm('確定要刪除此產品及其所有相關資料嗎？')) {
      db.deleteProduct(pid);
      setSavedProducts(db.getProducts());
      if (currentExtractionProductId === pid) {
