        responseSchema: outputSchema,
        temperature: 0.1, // Low temperature for factual extraction
      }
    });

    // Cleanup response text in case it contains Markdown code blocks
    let rawText = response.text || "{}";
    rawText = rawText.trim();
    if (rawText.startsWith("```json")) {
      rawText = rawText.replace(/^```json/, "").replace(/```$/, "");
    } else if (rawText.startsWith("```")) {
      rawText = rawText.replace(/^```/, "").replace(/```$/, "");
    }

    return JSON.parse(rawText);
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to process the document. Please try again.");
  }
}

import { GoogleGenAI, Type, Schema } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
你是一位高階藥品安全監視（PV）資料擷取專家。請從使用者提供的「仿單」（可能是圖片、PDF文件或純文字）中，建立完整且精確的 AE 主檔 JSON。

**核心任務：**
請掃描整份文件，提取**所有**提及的「不良反應（Adverse Events/Side Effects）」或「副作用」。
**關鍵要求：同時抓取「表格中的精確數值」與「文字段落中的列舉項目」。**

目標輸出結構：
1. product_name（字串）
2. label_version_date（若無則留空）
3. frequency_legend（仿單頻率分類定義原文，盡量保留）
4. ae_master（陣列，每一筆代表一個 AE term）：
   - soc（系統器官分類，字串。若文中未提及 SOC，請根據醫學知識自行推斷填入，或標記 "Unknown"）
   - ae_term_raw（仿單原文 AE term，字串）
   - ae_terms_split（字串陣列：若同一格或同一句有多個 AE，必須逐條拆分）
   - label_frequency_text（如：常見/12.5%...，字串）
   - label_threshold_upper_pct（數字：以「上限%」做門檻）
   - mapping_rule_note（你如何推導門檻）

詳細解析規則：

1. **搜尋範圍 (全面覆蓋)**：
   - **統計表格 (Tables)**：這通常包含最精確的數據。
     - 若表格有區分群組（如：本藥品組 vs 安慰劑組），**請只提取「本藥品組」的數值**。
     - 若表格欄位是發生率（Incidence %），請直接提取該數字。
   - **文字段落 (Paragraphs)**：例如「罕見的不良反應包含：A病、B病...」。
   - **上市後經驗 (Post-marketing experience)**：通常為純文字條列，不可遺漏。

2. **頻率與門檻值 (Threshold) 判定邏輯 - 數值優先！**：
   - **最高優先 (表格/文中精確數值)**：
     - 若來源提供具體數字（例如 "1.5%"、"12%"、"5/100"），請直接提取該數字作為 \`label_threshold_upper_pct\`。
     - **不要**將 1.5% 轉化為 "常見" 的通用門檻 (10%)，請保留 1.5 精確值。

   - **次要優先 (文字定義/區間)**：
     - 若僅提及「常見」、「罕見」等分類，請依據 CIOMS III 定義設定上限：
     - **十分常見 (Very Common)**：定義為 ≧ 1/10。預設門檻為 **10%**。
     - **常見 (Common)**：定義為 ≧ 1/100 至 < 1/10。預設門檻為 **10%**。
     - **不常見 (Uncommon)**：定義為 ≧ 1/1,000 至 < 1/100。預設門檻為 **1%**。
     - **罕見 (Rare)**：定義為 ≧ 1/10,000 至 < 1/1,000。預設門檻為 **0.1%**。
     - **十分罕見 (Very Rare)**：定義為 < 1/10,000。預設門檻為 **0.01%**。
     - **頻率未知**：設定為 **0%**。

3. **拆分規則 (Splitting)**：
   - 請將連續列舉的症狀拆分為獨立項目。
   - 分隔符號包含：頓號「、」、逗號「,」、分號「;」、換行符號。
   - 若同時包含中英文，請保留兩者。
     例："心悸 (Palpitations)" -> split 為 ["心悸", "Palpitations"]。

4. **資料清理**：
   - 確保提取數量最大化，寧可多抓不可遺漏。
   - 若同一 AE 在表格中有數值 (5%)，在文中又提到是「常見」，請優先保留表格中的精確數值 (5%) 版本。
`;

// Define the response schema using strict typing
const outputSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    product_name: { type: Type.STRING, description: "Name of the drug product" },
    label_version_date: { type: Type.STRING, description: "Date of the label version if available" },
    frequency_legend: { type: Type.STRING, description: "Original text defining frequency categories" },
    ae_master: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          soc: { type: Type.STRING, description: "System Organ Class (Inferred if missing)" },
          ae_term_raw: { type: Type.STRING, description: "Original AE term from the text" },
          ae_terms_split: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "Split terms for database indexing"
          },
          label_frequency_text: { type: Type.STRING, description: "Frequency category text (e.g., Common or 12.5%)" },
          label_threshold_upper_pct: { type: Type.NUMBER, description: "Numeric upper threshold percentage" },
          mapping_rule_note: { type: Type.STRING, description: "Explanation of the mapping logic used" },
        },
        required: ["soc", "ae_term_raw", "ae_terms_split", "label_frequency_text", "label_threshold_upper_pct", "mapping_rule_note"]
      }
    }
  },
  required: ["product_name", "ae_master"]
};

export interface FileInput {
  data: string;     // Base64 string
  mimeType: string; // e.g., 'image/png', 'application/pdf'
}

export async function extractAEMaster(textInput: string, fileInput?: FileInput) {
  const parts: any[] = [];

  if (fileInput) {
    parts.push({
      inlineData: {
        mimeType: fileInput.mimeType,
        data: fileInput.data
      }
    });
  }

  if (textInput) {
    parts.push({ text: textInput });
  }

  if (parts.length === 0) {
    throw new Error("No input provided");
  }

  // Use a model capable of multimodal understanding (images and PDFs)
  const modelId = "gemini-3-flash-preview";

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: {
        role: 'user',
        parts: parts
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: outputSchema,
        temperature: 0.1, // Low temperature for factual extraction
        maxOutputTokens: 8192, // Increased from default to handle large AE lists
      }
    });

    // Cleanup response text in case it contains Markdown code blocks
    let rawText = response.text || "{}";
    rawText = rawText.trim();
    if (rawText.startsWith("```json")) {
      rawText = rawText.replace(/^```json/, "").replace(/```$/, "");
    } else if (rawText.startsWith("```")) {
      rawText = rawText.replace(/^```/, "").replace(/```$/, "");
    }

    // Attempt to parse
    try {
      return JSON.parse(rawText);
    } catch (parseError) {
      console.error("JSON Parse Error. Raw Text:", rawText);
      throw new Error(`Failed to parse AI response. The model output might be incomplete. (Length: ${rawText.length})`);
    }
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    throw new Error(error.message || "Failed to process the document. Please try again.");
  }
}

import React, { useState, useEffect } from 'react';
import { extractAEMaster, FileInput } from './services/gemini';
import { performAnalysis, AnalysisReport } from './services/analysis';
import { db, Product, LabelAeMaster, QuarterlyAeMonitor } from './services/db';
import { Clipboard, Upload, FileText, Activity, AlertCircle, Check, Database, BarChart3, Plus, Trash2, ArrowRight, Save, FolderOpen, Table, History, ToggleLeft, ToggleRight, FileType, AlertTriangle, X, Edit2, Calculator } from 'lucide-react';

export default function App() {
  // Navigation State
  const [activeMode, setActiveMode] = useState<'generator' | 'monitor' | 'library'>('generator');

  // Generator State
  const [textInput, setTextInput] = useState('');
  const [uploadedFile, setUploadedFile] = useState<File | null>(null);
  const [fileDataUrl, setFileDataUrl] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [masterResult, setMasterResult] = useState<any>(null); // The JSON from Gemini
  const [currentExtractionProductId, setCurrentExtractionProductId] = useState<string | null>(null); // Tracks the ID if saved
  const [error, setError] = useState<string | null>(null);
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved'>('idle');

  // Monitoring State
  // Quarter selection split into Year and Q part
  const [selYear, setSelYear] = useState(new Date().getFullYear().toString());
  const [selQ, setSelQ] = useState('Q1');

  // Derived quarter string for logic (e.g., "2025Q1")
  const quarter = `${selYear}${selQ}`;

  // Exposure Calculation State
  const [salesVolume, setSalesVolume] = useState<string>('');
  const [dailyDosage, setDailyDosage] = useState<string>('');
  const [exposureUnit, setExposureUnit] = useState('季'); // Default to Quarter
  const [exposureVal, setExposureVal] = useState<string>(''); // Calculated result

  const [inputCounts, setInputCounts] = useState<{term: string, count: string}[]>([{term: '', count: ''}]);
  const [analysisReport, setAnalysisReport] = useState<AnalysisReport | null>(null);
  const [showAllTerms, setShowAllTerms] = useState(false);

  // Database Integration State
  const [savedProducts, setSavedProducts] = useState<Product[]>([]);
  const [selectedProductId, setSelectedProductId] = useState<string>('');
  const [monitorSaveStatus, setMonitorSaveStatus] = useState<'idle' | 'saved'>('idle');
  // Trigger to force re-render of library view when DB changes
  const [dbUpdateTrigger, setDbUpdateTrigger] = useState(0);

  // Refresh products list
  useEffect(() => {
    setSavedProducts(db.getProducts());
  }, [activeMode, dbUpdateTrigger]);

  // Effect: Calculate Exposure Value whenever inputs change
  useEffect(() => {
    const sales = parseFloat(salesVolume);
    const dosage = parseFloat(dailyDosage);

    if (!isNaN(sales) && !isNaN(dosage) && dosage > 0) {
      let days = 1;
      switch (exposureUnit) {
        case '年': days = 365; break;
        case '季': days = 90; break; // 3 months * 30 days
        case '月': days = 30; break;
        case '日': days = 1; break;
        default: days = 1;
      }

      // Formula: Sales / (Dosage * Days)
      const calculatedExposure = sales / (dosage * days);

      // Round to 2 decimal places for display
      setExposureVal(calculatedExposure.toFixed(2));
    } else {
      setExposureVal('');
    }
  }, [salesVolume, dailyDosage, exposureUnit]);

  // Effect to re-run analysis when showAllTerms toggles
  useEffect(() => {
    if (analysisReport && masterResult) {
      runAnalysis();
    }
  }, [showAllTerms]);

  // --- Handlers for Generator ---
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setUploadedFile(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setFileDataUrl(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleClearFile = (e: React.MouseEvent) => {
    e.preventDefault();
    setUploadedFile(null);
    setFileDataUrl(null);
  };

  const handleProcess = async () => {
    if (!textInput && !uploadedFile) {
      setError("請提供文字描述或上傳檔案");
      return;
    }

    setLoading(true);
    setError(null);
    setMasterResult(null);
    setCurrentExtractionProductId(null); // Reset ID for new extraction
    setSaveStatus('idle');

    try {
      let fileInput: FileInput | undefined = undefined;
      if (uploadedFile && fileDataUrl) {
        // extract base64 from dataUrl (remove "data:xxxx;base64,")
        const base64 = fileDataUrl.split(',')[1];
        fileInput = {
          data: base64,
          mimeType: uploadedFile.type
        };
      }

      const data = await extractAEMaster(textInput, fileInput);
      setMasterResult(data);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "發生錯誤，請檢查 API Key 或重試。");
    } finally {
      setLoading(false);
    }
  };

  // --- Master Result Editing Handlers ---

  const handleManualCreate = () => {
    setMasterResult({
      product_name: "New Product (Manual)",
      label_version_date: new Date().toISOString().split('T')[0],
      frequency_legend: "Manual Entry",
      ae_master: []
    });
    setError(null);
    setSaveStatus('idle');
    setCurrentExtractionProductId(null);
  };

  const handleResultChange = (index: number, field: string, value: any) => {
    if (!masterResult) return;
    const newAeMaster = [...masterResult.ae_master];

    if (field === 'ae_terms_split') {
      // Input comes as string, split by comma for storage
      newAeMaster[index] = {
        ...newAeMaster[index],
        ae_terms_split: value.split(/[,，、;]+/).map((t: string) => t.trim()).filter((t: string) => t)
      };
    } else {
      newAeMaster[index] = { ...newAeMaster[index], [field]: value };
    }

    setMasterResult({ ...masterResult, ae_master: newAeMaster });
    setSaveStatus('idle'); // Reset save status if modified
  };

  const handleDeleteResultItem = (index: number) => {
    if (!masterResult) return;
    const newAeMaster = masterResult.ae_master.filter((_: any, i: number) => i !== index);
    setMasterResult({ ...masterResult, ae_master: newAeMaster });
    setSaveStatus('idle');
  };

  const handleAddResultItem = () => {
    if (!masterResult) return;
    const newItem = {
      soc: "",
      ae_term_raw: "",
      ae_terms_split: [],
      label_frequency_text: "",
      label_threshold_upper_pct: 0,
      mapping_rule_note: "Manual Entry"
    };
    setMasterResult({ 
      ...masterResult, 
      ae_master: [...(masterResult.ae_master || []), newItem] 
    });
    setSaveStatus('idle');
  };

  const handleSaveToDb = () => {
    if (!masterResult) return;
    try {
      // If we already saved this session, update the existing ID. Otherwise undefined (create new).
      const newId = db.saveExtractedMaster(masterResult, currentExtractionProductId || undefined);

      setCurrentExtractionProductId(newId);
      setSaveStatus('saved');
      setSavedProducts(db.getProducts());

      // Auto select this new product if user goes to monitor tab
      setSelectedProductId(newId);
    } catch (e) {
      console.error(e);
      alert("儲存失敗");
    }
  };

  // --- Handlers for Monitoring ---
  const handleLoadProduct = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const pid = e.target.value;
    setSelectedProductId(pid);
    if (pid) {
      const analysisFormat = db.getMasterForAnalysis(pid);
      setMasterResult(analysisFormat);
      setAnalysisReport(null); // Clear previous report
