import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
你是一位高階藥品安全監視（PV）資料擷取專家。請從使用者提供的「仿單」（可能是圖片、PDF文件或純文字）中，建立完整且精確的 AE 主檔 JSON。

**核心任務：**
請掃描整份文件，提取**所有**提及的「不良反應（Adverse Events/Side Effects）」或「副作用」。
**關鍵要求：同時抓取「表格中的精確數值」與「文字段落中的列舉項目」。**

目標輸出結構 (JSON Format):
{
  "product_name": "Name of the drug",
  "label_version_date": "Date string or empty",
  "frequency_legend": "Original text defining frequencies",
  "ae_master": [
    {
      "soc": "System Organ Class (Inferred if missing)",
      "ae_term_raw": "Original term",
      "ae_terms_split": ["Term 1", "Term 2"],
      "label_frequency_text": "e.g. Common, 10%",
      "label_threshold_upper_pct": 10.0,
      "mapping_rule_note": "Reasoning"
    }
  ]
}

詳細解析規則：

1. **搜尋範圍 (全面覆蓋)**：
   - **統計表格 (Tables)**：這通常包含最精確的數據。
     - 若表格有區分群組（如：本藥品組 vs 安慰劑組），**請只提取「本藥品組」的數值**。
     - 若表格欄位是發生率（Incidence %），請直接提取該數字。
   - **文字段落 (Paragraphs)**：例如「罕見的不良反應包含：A病、B病...」。
   - **上市後經驗 (Post-marketing experience)**：通常為純文字條列，不可遺漏。

2. **頻率與門檻值 (Threshold) 判定邏輯 - 數值優先！**：
   - **最高優先 (表格/文中精確數值)**：
     - 若來源提供具體數字（例如 "1.5%"、"12%"、"5/100"），請直接提取該數字作為 \`label_threshold_upper_pct\`。
     - **不要**將 1.5% 轉化為 "常見" 的通用門檻 (10%)，請保留 1.5 精確值。

   - **次要優先 (文字定義/區間)**：
     - 若僅提及「常見」、「罕見」等分類，請依據 CIOMS III 定義設定上限：
     - **十分常見 (Very Common)**：定義為 ≧ 1/10。預設門檻為 **10%**。
     - **常見 (Common)**：定義為 ≧ 1/100 至 < 1/10。預設門檻為 **10%**。
     - **不常見 (Uncommon)**：定義為 ≧ 1/1,000 至 < 1/100。預設門檻為 **1%**。
     - **罕見 (Rare)**：定義為 ≧ 1/10,000 至 < 1/1,000。預設門檻為 **0.1%**。
     - **十分罕見 (Very Rare)**：定義為 < 1/10,000。預設門檻為 **0.01%**。
     - **頻率未知**：設定為 **0%**。

3. **拆分規則 (Splitting)**：
   - 請將連續列舉的症狀拆分為獨立項目。
   - 分隔符號包含：頓號「、」、逗號「,」、分號「;」、換行符號。
   - 若同時包含中英文，請保留兩者。
     例："心悸 (Palpitations)" -> split 為 ["心悸", "Palpitations"]。

4. **資料清理**：
   - 確保提取數量最大化，寧可多抓不可遺漏。
   - 若同一 AE 在表格中有數值 (5%)，在文中又提到是「常見」，請優先保留表格中的精確數值 (5%) 版本。
   - 回傳格式必須為純 JSON，不要包含 Markdown code block。
`;

export interface FileInput {
  data: string;     // Base64 string
  mimeType: string; // e.g., 'image/png', 'application/pdf'
}

export async function extractAEMaster(textInput: string, fileInput?: FileInput) {
  const parts: any[] = [];

  if (fileInput) {
    parts.push({
      inlineData: {
        mimeType: fileInput.mimeType,
        data: fileInput.data
      }
    });
  }

  if (textInput) {
    parts.push({ text: textInput });
  }

  if (parts.length === 0) {
    throw new Error("No input provided");
  }

  // Use a model capable of multimodal understanding (images and PDFs)
  const modelId = "gemini-3-flash-preview";

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: {
        role: 'user',
        parts: parts
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        // responseSchema is removed to avoid truncation issues with complex large JSONs in Preview models
        temperature: 0.1, // Low temperature for factual extraction
        maxOutputTokens: 8192, // Increased from default to handle large AE lists
      }
    });

    // Cleanup response text in case it contains Markdown code blocks
    let rawText = response.text || "{}";
    rawText = rawText.trim();
    if (rawText.startsWith("```json")) {
      rawText = rawText.replace(/^```json/, "").replace(/```$/, "");
    } else if (rawText.startsWith("```")) {
      rawText = rawText.replace(/^```/, "").replace(/```$/, "");
    }

    // Attempt to parse
    try {
      return JSON.parse(rawText);
    } catch (parseError) {
      console.error("JSON Parse Error. Raw Text:", rawText);
      throw new Error(`Failed to parse AI response. The model output might be incomplete. (Length: ${rawText.length})`);
    }
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    throw new Error(error.message || "Failed to process the document. Please try again.");
  }
}

// Simple ID generator
const generateId = () => Date.now().toString(36) + Math.random().toString(36).substring(2);

// 1. Products Table
export interface Product {
  product_id: string;
  product_name: string;
  label_version_date: string;
}

// 2. Label AE Master Table
export interface LabelAeMaster {
  id?: string; // Internal ID for management
  product_id: string;
  soc: string;
  ae_term: string; // This corresponds to the split term
  label_freq_text: string;
  threshold_upper_pct: number;
  created_at: string;
  group_id?: string; // ID to group split terms that belong to the same original entry
}

// 3. Quarterly AE Monitor Table
export interface QuarterlyAeMonitor {
  id?: string; // Internal ID
  product_id: string;
  quarter: string;
  exposure_value: number;
  exposure_unit: string;
  ae_term: string;
  count: number;
  rate_pct: number;
  threshold_pct: number;
  status: 'normal' | 'yellow' | 'red'; // Simplified status as per requirement (mapped from internal)
  generated_at: string;
}

// Helper interface for grouped batches
export interface MonitorBatch {
  generated_at: string;
  product_id: string;
  quarter: string;
  exposure_value: number;
  exposure_unit: string;
  record_count: number;
  alert_count: number;
  unexpected_count: number;
}

const DB_KEYS = {
  PRODUCTS: 'pv_db_products',
  MASTER: 'pv_db_label_ae_master',
  MONITOR: 'pv_db_quarterly_ae_monitor'
};

// --- Data Access Layer ---

export const db = {
  // Products
  getProducts: (): Product[] => {
    const str = localStorage.getItem(DB_KEYS.PRODUCTS);
    return str ? JSON.parse(str) : [];
  },

  saveProduct: (product: Product) => {
    const products = db.getProducts();
    // Update if exists or add new
    const idx = products.findIndex(p => p.product_id === product.product_id);
    if (idx >= 0) {
      products[idx] = product;
    } else {
      products.push(product);
    }
    localStorage.setItem(DB_KEYS.PRODUCTS, JSON.stringify(products));
  },

  deleteProduct: (productId: string) => {
    const products = db.getProducts().filter(p => p.product_id !== productId);
    localStorage.setItem(DB_KEYS.PRODUCTS, JSON.stringify(products));

    // Cascade delete master
    const masters = db.getLabelAeMasters().filter(m => m.product_id !== productId);
    localStorage.setItem(DB_KEYS.MASTER, JSON.stringify(masters));

    // Cascade delete monitor records
    const monitors = db.getQuarterlyAeMonitors().filter(m => m.product_id !== productId);
    localStorage.setItem(DB_KEYS.MONITOR, JSON.stringify(monitors));
  },

  // Master
  getLabelAeMasters: (productId?: string): LabelAeMaster[] => {
    const str = localStorage.getItem(DB_KEYS.MASTER);
    const all: LabelAeMaster[] = str ? JSON.parse(str) : [];
    if (productId) {
      return all.filter(m => m.product_id === productId);
    }
    return all;
  },

  saveLabelAeMasters: (masters: LabelAeMaster[]) => {
    const current = db.getLabelAeMasters();
    // If we are saving masters for a product, we should probably clear old ones for that product first to avoid duplicates if re-saved
    const productIds = new Set(masters.map(m => m.product_id));
    const filteredCurrent = current.filter(m => !productIds.has(m.product_id));

    const updated = [...filteredCurrent, ...masters];
    localStorage.setItem(DB_KEYS.MASTER, JSON.stringify(updated));
  },

  // Monitor
  getQuarterlyAeMonitors: (productId?: string): QuarterlyAeMonitor[] => {
    const str = localStorage.getItem(DB_KEYS.MONITOR);
    const all: QuarterlyAeMonitor[] = str ? JSON.parse(str) : [];
    if (productId) {
      return all.filter(m => m.product_id === productId);
    }
    return all;
  },

  // Get distinct batches (reports) for display in library
  getMonitorBatches: (): MonitorBatch[] => {
    const all = db.getQuarterlyAeMonitors();
    const batches = new Map<string, MonitorBatch>();

    all.forEach(record => {
      // Group by generated_at as a batch ID
      const key = record.generated_at;

      if (!batches.has(key)) {
        batches.set(key, {
          generated_at: record.generated_at,
          product_id: record.product_id,
          quarter: record.quarter,
          exposure_value: record.exposure_value,
          exposure_unit: record.exposure_unit,
          record_count: 0,
          alert_count: 0,
          unexpected_count: 0
        });
      }

      const batch = batches.get(key)!;
      batch.record_count++;
      if (record.status === 'red') {
        // We use 'red' for both alert and unexpected in DB, need to distinguish?
        // In the App.tsx logic: status=red for 'alert' OR 'unexpected'.
        // Let's assume standard red is alert.
        // Actually the current DB implementation simplifies statuses.
        // Let's just count reds.
        batch.alert_count++;
      }
      // If we want to distinguish unexpected strictly, we'd need to check if AE term exists in master, 
      // but that's expensive here. For overview, total alerts (red) is enough.
    });

    // Sort by date desc
    return Array.from(batches.values()).sort((a, b) => 
      new Date(b.generated_at).getTime() - new Date(a.generated_at).getTime()
    );
  },

  // Get records for a specific batch
  getMonitorRecordsByBatch: (generatedAt: string): QuarterlyAeMonitor[] => {
    const all = db.getQuarterlyAeMonitors();
    return all.filter(r => r.generated_at === generatedAt);
  },

  deleteMonitorBatch: (generatedAt: string) => {
    const current = db.getQuarterlyAeMonitors();
    const updated = current.filter(m => m.generated_at !== generatedAt);
    localStorage.setItem(DB_KEYS.MONITOR, JSON.stringify(updated));
  },

  saveQuarterlyAeMonitors: (records: QuarterlyAeMonitor[]) => {
    const current = db.getQuarterlyAeMonitors();
    // Append new records (history)
    const updated = [...current, ...records];
    localStorage.setItem(DB_KEYS.MONITOR, JSON.stringify(updated));
  },

  deleteMonitorRecord: (recordId: string) => {
    const current = db.getQuarterlyAeMonitors();
    const updated = current.filter(m => m.id !== recordId);
    localStorage.setItem(DB_KEYS.MONITOR, JSON.stringify(updated));
  },

  // --- High Level Actions ---

  // Save a full master extraction result
  saveExtractedMaster: (data: any, existingProductId?: string) => {
    const productId = existingProductId || generateId();
    const now = new Date().toISOString();

    const product: Product = {
      product_id: productId,
      product_name: data.product_name,
      label_version_date: data.label_version_date || ''
    };

    const masters: LabelAeMaster[] = [];
    data.ae_master.forEach((item: any) => {
      const groupId = generateId(); // Group terms that belong to the same entry
      item.ae_terms_split.forEach((term: string) => {
        masters.push({
          id: generateId(),
          product_id: productId,
          soc: item.soc,
          ae_term: term,
          label_freq_text: item.label_frequency_text,
          threshold_upper_pct: item.label_threshold_upper_pct,
          created_at: now,
          group_id: groupId
        });
      });
    });

    db.saveProduct(product);
    db.saveLabelAeMasters(masters);
    return productId;
  },

  // Convert DB master rows back to format needed for analysis
  getMasterForAnalysis: (productId: string) => {
    const rows = db.getLabelAeMasters(productId);

    // Group rows by group_id to reconstruct the master items
    const groupedMap = new Map<string, any>();

    rows.forEach(r => {
      // Use group_id if available. If not (legacy data), use id to keep them separate.
      const gid = r.group_id || r.id || generateId();

      if (!groupedMap.has(gid)) {
        groupedMap.set(gid, {
          soc: r.soc,
          ae_term_raw: "", // Reconstructed below
          ae_terms_split: [],
          label_frequency_text: r.label_freq_text,
          label_threshold_upper_pct: r.threshold_upper_pct,
          mapping_rule_note: "Loaded from DB"
        });
      }

      const group = groupedMap.get(gid);
      group.ae_terms_split.push(r.ae_term);
    });

    const ae_master = Array.from(groupedMap.values()).map(item => ({
      ...item,
      // Create a display string for raw term
      ae_term_raw: item.ae_terms_split.join(' / ')
    }));

    return { 
      product_name: "", // Not strictly needed for analysis logic
      ae_master 
    };
  }
};

