    const sales = parseFloat(salesVolume);
    const dosage = parseFloat(dailyDosage);

    if (!isNaN(sales) && !isNaN(dosage) && dosage > 0) {
      let days = 1;
      switch (exposureUnit) {
        case '年': days = 365; break;
        case '季': days = 90; break; // 3 months * 30 days
        case '月': days = 30; break;
        case '日': days = 1; break;
        default: days = 1;
      }

      // Formula: Sales / (Dosage * Days)
      const calculatedExposure = sales / (dosage * days);

      // Round to 2 decimal places for display
      setExposureVal(calculatedExposure.toFixed(2));
    } else {
      setExposureVal('');
    }
  }, [salesVolume, dailyDosage, exposureUnit]);

  // Effect to re-run analysis when showAllTerms toggles
  useEffect(() => {
    if (analysisReport && masterResult) {
      runAnalysis();
    }
  }, [showAllTerms]);

  // --- Handlers for Generator ---
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setUploadedFile(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setFileDataUrl(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleClearFile = (e: React.MouseEvent) => {
    e.preventDefault();
    setUploadedFile(null);
    setFileDataUrl(null);
  };

  const handleProcess = async () => {
    if (!textInput && !uploadedFile) {
      setError("請提供文字描述或上傳檔案");
      return;
    }

    setLoading(true);
    setError(null);
    setMasterResult(null);
    setCurrentExtractionProductId(null); // Reset ID for new extraction
    setSaveStatus('idle');

    try {
      let fileInput: FileInput | undefined = undefined;
      if (uploadedFile && fileDataUrl) {
        // extract base64 from dataUrl (remove "data:xxxx;base64,")
        const base64 = fileDataUrl.split(',')[1];
        fileInput = {
          data: base64,
          mimeType: uploadedFile.type
        };
      }

      const data = await extractAEMaster(textInput, fileInput);
      setMasterResult(data);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "發生錯誤，請檢查 API Key 或重試。");
    } finally {
      setLoading(false);
    }
  };

  // --- Master Result Editing Handlers ---

  const handleManualCreate = () => {
    setMasterResult({
      product_name: "New Product (Manual)",
      label_version_date: new Date().toISOString().split('T')[0],
      frequency_legend: "Manual Entry",
      ae_master: []
    });
    setError(null);
    setSaveStatus('idle');
    setCurrentExtractionProductId(null);
  };

  const handleResultChange = (index: number, field: string, value: any) => {
    if (!masterResult) return;
    const newAeMaster = [...masterResult.ae_master];

    if (field === 'ae_terms_split') {
      // Input comes as string, split by comma for storage
      newAeMaster[index] = {
        ...newAeMaster[index],
        ae_terms_split: value.split(/[,，、;]+/).map((t: string) => t.trim()).filter((t: string) => t)
      };
    } else {
      newAeMaster[index] = { ...newAeMaster[index], [field]: value };
    }

    setMasterResult({ ...masterResult, ae_master: newAeMaster });
    setSaveStatus('idle'); // Reset save status if modified
  };

  const handleDeleteResultItem = (index: number) => {
    if (!masterResult) return;
    const newAeMaster = masterResult.ae_master.filter((_: any, i: number) => i !== index);
    setMasterResult({ ...masterResult, ae_master: newAeMaster });
    setSaveStatus('idle');
  };

  const handleAddResultItem = () => {
    if (!masterResult) return;
    const newItem = {
      soc: "",
      ae_term_raw: "",
      ae_terms_split: [],
      label_frequency_text: "",
      label_threshold_upper_pct: 0,
      mapping_rule_note: "Manual Entry"
    };
    setMasterResult({ 
      ...masterResult, 
      ae_master: [...(masterResult.ae_master || []), newItem] 
    });
    setSaveStatus('idle');
  };

  const handleSaveToDb = () => {
    if (!masterResult) return;
    try {
      // If we already saved this session, update the existing ID. Otherwise undefined (create new).
      const newId = db.saveExtractedMaster(masterResult, currentExtractionProductId || undefined);

      setCurrentExtractionProductId(newId);
      setSaveStatus('saved');
      setSavedProducts(db.getProducts());

      // Auto select this new product if user goes to monitor tab
      setSelectedProductId(newId);
    } catch (e) {
      console.error(e);
      alert("儲存失敗");
    }
  };

  // --- Handlers for Monitoring ---
  const handleLoadProduct = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const pid = e.target.value;
    setSelectedProductId(pid);
    if (pid) {
      const analysisFormat = db.getMasterForAnalysis(pid);
      setMasterResult(analysisFormat);
      setAnalysisReport(null); // Clear previous report
      setMonitorSaveStatus('idle');
    } else {
      setMasterResult(null);
    }
  };

  const handleAddRow = () => {
    setInputCounts([...inputCounts, { term: '', count: '' }]);
  };

  const handleRemoveRow = (idx: number) => {
    setInputCounts(inputCounts.filter((_, i) => i !== idx));
  };

  const handleInputChange = (idx: number, field: 'term' | 'count', value: string) => {
    const newRows = [...inputCounts];
    newRows[idx] = { ...newRows[idx], [field]: value };
    setInputCounts(newRows);
  };

  const handleQuickAddTerm = (term: string) => {
    const lastRow = inputCounts[inputCounts.length - 1];
    if (!lastRow.term && !lastRow.count) {
      handleInputChange(inputCounts.length - 1, 'term', term);
    } else {
      setInputCounts([...inputCounts, { term, count: '' }]);
    }
  };

  const runAnalysis = () => {
    if (!masterResult) {
      alert("請先載入產品或產生主檔");
      return;
    }
    const val = parseFloat(exposureVal);

    // VALIDATION ALERT
    if (!exposureVal || isNaN(val) || val <= 0) {
      alert("⚠️ 注意：尚未產生有效的暴露量！\n\n請完整填寫「銷售數量」與「每日使用量」，系統將自動計算分母。");
      return;
    }

    // Filter valid rows: Must have a term name. Count defaults to 0 if empty.
    const validCounts = inputCounts
      .filter(r => r.term.trim() !== '') 
      .map(r => ({
        term: r.term,
        count: parseInt(r.count, 10) || 0
      }));

    // Allow analysis even if validCounts is empty (Report will show 0 cases)
    const report = performAnalysis(masterResult, {
      quarter,
      exposure_value: val,
      exposure_unit: exposureUnit,
      ae_counts: validCounts
    }, {
      includeAllMasterTerms: showAllTerms
    });

    setAnalysisReport(report);
    setMonitorSaveStatus('idle');
  };

  const handleSaveAnalysis = () => {
    if (!analysisReport || !selectedProductId) {
      alert("需選擇產品並執行分析後才能儲存");
      return;
    }

    const records: QuarterlyAeMonitor[] = [];
    const now = new Date().toISOString();

    if (analysisReport.rows.length === 0) {
      // HANDLE EMPTY REPORT: Save a single record indicating No AEs
      const id = Date.now().toString(36) + Math.random().toString(36).substring(2);
      records.push({
        id,
        product_id: selectedProductId,
        quarter: quarter,
        exposure_value: parseFloat(exposureVal),
        exposure_unit: exposureUnit,
        ae_term: "本季無不良反應 (No Adverse Events)",
        count: 0,
        rate_pct: 0,
        threshold_pct: 0,
        status: 'normal',
        generated_at: now
      });
    } else {
      // Handle normal report with rows
      analysisReport.rows.forEach(row => {
        let status: 'normal' | 'yellow' | 'red' = 'normal';
        if (row.status === 'alert') status = 'red';
        if (row.status === 'warning') status = 'yellow';
        if (row.status === 'unexpected') status = 'red'; // Unexpected is also a RED flag in DB

        // Simple random ID generation
        const id = Date.now().toString(36) + Math.random().toString(36).substring(2);

        records.push({
          id,
          product_id: selectedProductId,
          quarter: quarter,
          exposure_value: parseFloat(exposureVal),
          exposure_unit: exposureUnit,
          ae_term: row.ae_term,
          count: row.count,
          rate_pct: row.incidence_rate_pct,
          threshold_pct: row.threshold_pct,
          status: status,
          generated_at: now
        });
      });
    }

    if (records.length > 0) {
       db.saveQuarterlyAeMonitors(records);
       setDbUpdateTrigger(prev => prev + 1); // Force library update
    }

    setMonitorSaveStatus('saved');
  };

