                      <h2 className="text-xl font-bold text-slate-900">稽核日誌 (Audit Trail)</h2>
                      <p className="text-slate-500 text-sm">GVP 規範要求之系統操作紀錄，僅供檢視，不可修改。</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-2 px-3 py-1 bg-slate-50 border border-slate-200 rounded text-xs text-slate-500">
                    <ScrollText size={14}/>
                    Total Logs: {systemLogs.length}
                  </div>
                </div>

                <div className="overflow-hidden border rounded-lg border-slate-200">
                  <table className="w-full text-sm text-left">
                    <thead className="bg-slate-50 text-slate-600 font-semibold border-b border-slate-200">
                      <tr>
                        <th className="px-4 py-3 w-48">Timestamp</th>
                        <th className="px-4 py-3 w-32">Action</th>
                        <th className="px-4 py-3 w-32">Module</th>
                        <th className="px-4 py-3">Description</th>
                        <th className="px-4 py-3 w-32">User</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                      {systemLogs.map((log) => (
                        <tr key={log.id} className="hover:bg-slate-50">
                          <td className="px-4 py-3 text-slate-500 font-mono text-xs whitespace-nowrap">
                             {new Date(log.timestamp).toLocaleString()}
                          </td>
                          <td className="px-4 py-3">
                             <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wide border ${
                               log.action_type === 'CREATE' ? 'bg-green-50 text-green-700 border-green-200' :
                               log.action_type === 'UPDATE' ? 'bg-blue-50 text-blue-700 border-blue-200' :
                               log.action_type === 'DELETE' ? 'bg-red-50 text-red-700 border-red-200' :
                               log.action_type === 'EXPORT' ? 'bg-purple-50 text-purple-700 border-purple-200' :
                               'bg-slate-100 text-slate-700 border-slate-200'
                             }`}>
                               {log.action_type}
                             </span>
                          </td>
                          <td className="px-4 py-3 text-xs font-semibold text-slate-600">
                             {log.module}
                          </td>
                          <td className="px-4 py-3 text-slate-800">
                             {log.description}
                          </td>
                          <td className="px-4 py-3 text-xs text-slate-400">
                             {log.user}
                          </td>
                        </tr>
                      ))}
                      {systemLogs.length === 0 && (
                         <tr><td colSpan={5} className="px-4 py-8 text-center text-slate-400">尚無系統日誌</td></tr>
                      )}
                    </tbody>
                  </table>
                </div>
             </div>
           </div>
        )}

        {/* --- MODALS --- */}

        {/* Product Details Modal */}
        <DetailModal 
          isOpen={!!viewingProduct} 
          onClose={() => setViewingProduct(null)}
          title={viewingProduct ? `Product Master: ${viewingProduct.product.product_name}` : ''}
        >
          {viewingProduct && (
            <div className="space-y-4">
               <div className="flex gap-4 text-sm text-slate-500 mb-4 bg-white p-3 rounded border border-slate-200">
                  <div><strong>ID:</strong> {viewingProduct.product.product_id}</div>
                  <div><strong>Version Date:</strong> {viewingProduct.product.label_version_date}</div>
                  <div><strong>Total AE Terms:</strong> {viewingProduct.masters.length}</div>
               </div>

               <table className="w-full text-sm text-left border-collapse">
                 <thead className="bg-slate-100 text-slate-700 text-xs uppercase sticky top-0">
                   <tr>
                     <th className="px-3 py-2 border-b">SOC</th>
                     <th className="px-3 py-2 border-b">AE Term</th>
                     <th className="px-3 py-2 border-b">Freq Text</th>
                     <th className="px-3 py-2 border-b text-right">Threshold %</th>
                   </tr>
                 </thead>
                 <tbody className="divide-y divide-slate-100">
                   {viewingProduct.masters.map(m => (
                     <tr key={m.id} className="hover:bg-slate-50">
                       <td className="px-3 py-2 text-xs text-slate-500">{m.soc}</td>
                       <td className="px-3 py-2 font-medium">{m.ae_term}</td>
                       <td className="px-3 py-2 text-xs text-slate-500">{m.label_freq_text}</td>
                       <td className="px-3 py-2 text-right font-mono">{m.threshold_upper_pct}%</td>
                     </tr>
                   ))}
                 </tbody>
               </table>
            </div>
          )}
        </DetailModal>

        {/* Batch Report Modal */}
        <DetailModal 
          isOpen={!!viewingBatch} 
          onClose={() => setViewingBatch(null)}
          title={viewingBatch ? (
            <div className="flex items-center gap-2">
              <span className="bg-slate-100 px-2 py-1 rounded text-sm font-mono">{viewingBatch.batch.quarter}</span>
              <span>監測報告內容</span>
              <span className="text-xs font-normal text-slate-500 ml-2">({new Date(viewingBatch.batch.generated_at).toLocaleString()})</span>
            </div>
          ) : ''}
        >
          {viewingBatch && (
            <div className="space-y-4">
              <div className="flex flex-wrap gap-4 text-sm text-slate-500 mb-4 bg-white p-4 rounded border border-slate-200 shadow-sm">
                  <div className="flex items-center gap-1"><Database size={14}/> <strong>Product ID:</strong> {viewingBatch.batch.product_id}</div>
                  <div className="flex items-center gap-1"><Calculator size={14}/> <strong>Exposure:</strong> {viewingBatch.batch.exposure_value} {viewingBatch.batch.exposure_unit}</div>
                  <div className="flex items-center gap-1"><Activity size={14}/> <strong>Total Cases Checked:</strong> {viewingBatch.records.length}</div>
               </div>

               <table className="w-full text-sm text-left border-collapse">
                 <thead className="bg-slate-100 text-slate-700 text-xs uppercase sticky top-0">
                   <tr>
                     <th className="px-3 py-2 border-b">AE Term</th>
                     <th className="px-3 py-2 border-b text-right">Count</th>
                     <th className="px-3 py-2 border-b text-right">Rate %</th>
                     <th className="px-3 py-2 border-b text-right">Threshold %</th>
                     <th className="px-3 py-2 border-b text-center">Status</th>
                   </tr>
                 </thead>
                 <tbody className="divide-y divide-slate-100">
                   {viewingBatch.records.map(r => (
                     <tr key={r.id} className={`hover:bg-slate-50 ${r.status === 'red' ? 'bg-red-50' : r.status === 'yellow' ? 'bg-yellow-50' : ''}`}>
                       <td className="px-3 py-2 font-medium">{r.ae_term}</td>
                       <td className="px-3 py-2 text-right font-mono">{r.count}</td>
                       <td className="px-3 py-2 text-right font-mono font-bold text-slate-700">{r.rate_pct.toFixed(4)}%</td>
                       <td className="px-3 py-2 text-right font-mono text-slate-400">{r.threshold_pct}%</td>
                       <td className="px-3 py-2 text-center">
                         <span className={`px-2 py-0.5 rounded text-xs font-bold ${
                           r.status === 'red' ? 'bg-red-200 text-red-800' : 
                           r.status === 'yellow' ? 'bg-yellow-200 text-yellow-800' : 
                           'bg-green-100 text-green-800'
                         }`}>
                           {r.status.toUpperCase()}
                         </span>
                       </td>
                     </tr>
                   ))}
                 </tbody>
               </table>
            </div>
          )}
        </DetailModal>

      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { extractAEMaster, FileInput } from './services/gemini';
import { performAnalysis, AnalysisReport } from './services/analysis';
import { db, Product, LabelAeMaster, QuarterlyAeMonitor, MonitorBatch, SystemLog } from './services/db';
import { Clipboard, Upload, FileText, Activity, AlertCircle, Check, Database, BarChart3, Plus, Trash2, ArrowRight, Save, FolderOpen, Table, History, ToggleLeft, ToggleRight, FileType, AlertTriangle, X, Edit2, Calculator, Eye, List, Calendar, Download, ShieldCheck, ScrollText } from 'lucide-react';

// -- Sub-component: Detail Modal --
const DetailModal = ({ 
  isOpen, 
  onClose, 
  title, 
  children 
}: { 
  isOpen: boolean; 
  onClose: () => void; 
  title: React.ReactNode; 
  children?: React.ReactNode 
}) => {
  if (!isOpen) return null;
  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/40 backdrop-blur-[2px] p-4 animate-in fade-in duration-300">
      <div className="bg-white/95 backdrop-blur-sm rounded-xl shadow-2xl w-full max-w-4xl max-h-[90vh] flex flex-col border border-white/20">
        <div className="flex justify-between items-center px-6 py-4 border-b border-slate-100">
          <h3 className="text-lg font-bold text-slate-800">{title}</h3>
          <button onClick={onClose} className="p-1 hover:bg-slate-100 rounded-full transition-colors">
            <X size={20} className="text-slate-500" />
          </button>
        </div>
        <div className="overflow-y-auto p-6 bg-slate-50/50">
          {children}
        </div>
        <div className="px-6 py-4 border-t border-slate-100 bg-white/80 flex justify-end">
          <button onClick={onClose} className="px-4 py-2 bg-slate-100 text-slate-700 font-medium rounded-lg hover:bg-slate-200 transition-colors">
            關閉視窗
          </button>
        </div>
      </div>
    </div>
  );
};

export default function App() {
  // Navigation State
  const [activeMode, setActiveMode] = useState<'generator' | 'monitor' | 'library' | 'audit'>('generator');

  // Generator State
  const [textInput, setTextInput] = useState('');
  const [uploadedFile, setUploadedFile] = useState<File | null>(null);
  const [fileDataUrl, setFileDataUrl] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [masterResult, setMasterResult] = useState<any>(null); // The JSON from Gemini
  const [currentExtractionProductId, setCurrentExtractionProductId] = useState<string | null>(null); // Tracks the ID if saved
  const [error, setError] = useState<string | null>(null);
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved'>('idle');

  // Monitoring State
  // Quarter selection split into Year and Q part
  const [selYear, setSelYear] = useState(new Date().getFullYear().toString());
  const [selQ, setSelQ] = useState('Q1');

  // Derived quarter string for logic (e.g., "2025Q1")
  const quarter = `${selYear}${selQ}`;

  // Exposure Calculation State
  const [salesVolume, setSalesVolume] = useState<string>('');
  const [dailyDosage, setDailyDosage] = useState<string>('');
  const [exposureUnit, setExposureUnit] = useState('季'); // Default to Quarter
  const [exposureVal, setExposureVal] = useState<string>(''); // Calculated result

  const [inputCounts, setInputCounts] = useState<{term: string, count: string}[]>([{term: '', count: ''}]);
  const [analysisReport, setAnalysisReport] = useState<AnalysisReport | null>(null);
  const [showAllTerms, setShowAllTerms] = useState(false);

  // Database Integration State
  const [savedProducts, setSavedProducts] = useState<Product[]>([]);
  const [selectedProductId, setSelectedProductId] = useState<string>('');
  const [monitorSaveStatus, setMonitorSaveStatus] = useState<'idle' | 'saved'>('idle');
  // Trigger to force re-render of library view when DB changes
  const [dbUpdateTrigger, setDbUpdateTrigger] = useState(0);

  // Library Viewing State
  const [viewingProduct, setViewingProduct] = useState<{product: Product, masters: LabelAeMaster[]} | null>(null);
  const [viewingBatch, setViewingBatch] = useState<{batch: MonitorBatch, records: QuarterlyAeMonitor[]} | null>(null);
  const [systemLogs, setSystemLogs] = useState<SystemLog[]>([]);

  // Refresh products list
  useEffect(() => {
    setSavedProducts(db.getProducts());
    setSystemLogs(db.getLogs());
  }, [activeMode, dbUpdateTrigger]);

  // Effect: Calculate Exposure Value whenever inputs change
  useEffect(() => {
    const sales = parseFloat(salesVolume);
    const dosage = parseFloat(dailyDosage);

    if (!isNaN(sales) && !isNaN(dosage) && dosage > 0) {
      let days = 1;
      switch (exposureUnit) {
        case '年': days = 365; break;
        case '季': days = 90; break; // 3 months * 30 days
        case '月': days = 30; break;
        case '日': days = 1; break;
        default: days = 1;
      }

      // Formula: Sales / (Dosage * Days)
      const calculatedExposure = sales / (dosage * days);

      // Round to 2 decimal places for display
      setExposureVal(calculatedExposure.toFixed(2));
    } else {
      setExposureVal('');
    }
  }, [salesVolume, dailyDosage, exposureUnit]);

  // Effect to re-run analysis when showAllTerms toggles
  useEffect(() => {
    if (analysisReport && masterResult) {
      runAnalysis();
    }
  }, [showAllTerms]);

  // --- Handlers for Generator ---
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setUploadedFile(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setFileDataUrl(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleClearFile = (e: React.MouseEvent) => {
    e.preventDefault();
    setUploadedFile(null);
    setFileDataUrl(null);
  };

  const handleProcess = async () => {
    if (!textInput && !uploadedFile) {
      setError("請提供文字描述或上傳檔案");
      return;
    }

    setLoading(true);
    setError(null);
    setMasterResult(null);
    setCurrentExtractionProductId(null); // Reset ID for new extraction
    setSaveStatus('idle');

    try {
      let fileInput: FileInput | undefined = undefined;
      if (uploadedFile && fileDataUrl) {
        // extract base64 from dataUrl (remove "data:xxxx;base64,")
        const base64 = fileDataUrl.split(',')[1];
        fileInput = {
          data: base64,
          mimeType: uploadedFile.type
        };
      }

      const data = await extractAEMaster(textInput, fileInput);
      setMasterResult(data);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "發生錯誤，請檢查 API Key 或重試。");
    } finally {
      setLoading(false);
    }
  };

  // --- Master Result Editing Handlers ---

  const handleManualCreate = () => {
    setMasterResult({
      product_name: "New Product (Manual)",
      label_version_date: new Date().toISOString().split('T')[0],
      frequency_legend: "Manual Entry",
      ae_master: []
    });
    setError(null);
    setSaveStatus('idle');
    setCurrentExtractionProductId(null);
  };

  const handleResultChange = (index: number, field: string, value: any) => {
    if (!masterResult) return;
    const newAeMaster = [...masterResult.ae_master];

    if (field === 'ae_terms_split') {
      // Input comes as string, split by comma for storage
      newAeMaster[index] = {
        ...newAeMaster[index],
        ae_terms_split: value.split(/[,，、;]+/).map((t: string) => t.trim()).filter((t: string) => t)
      };
    } else {
      newAeMaster[index] = { ...newAeMaster[index], [field]: value };
    }

    setMasterResult({ ...masterResult, ae_master: newAeMaster });
    setSaveStatus('idle'); // Reset save status if modified
  };

  const handleDeleteResultItem = (index: number) => {
    if (!masterResult) return;
    const newAeMaster = masterResult.ae_master.filter((_: any, i: number) => i !== index);
    setMasterResult({ ...masterResult, ae_master: newAeMaster });
    setSaveStatus('idle');
  };

  const handleAddResultItem = () => {
    if (!masterResult) return;
    const newItem = {
      soc: "",
      ae_term_raw: "",
      ae_terms_split: [],
      label_frequency_text: "",
      label_threshold_upper_pct: 0,
      mapping_rule_note: "Manual Entry"
    };
    setMasterResult({ 
      ...masterResult, 
      ae_master: [...(masterResult.ae_master || []), newItem] 
    });
    setSaveStatus('idle');
  };

  const handleSaveToDb = () => {
    if (!masterResult) return;
    try {
      // If we already saved this session, update the existing ID. Otherwise undefined (create new).
      const newId = db.saveExtractedMaster(masterResult, currentExtractionProductId || undefined);

      setCurrentExtractionProductId(newId);
      setSaveStatus('saved');
      setSavedProducts(db.getProducts());

      // Auto select this new product if user goes to monitor tab
      setSelectedProductId(newId);
    } catch (e) {
      console.error(e);
      alert("儲存失敗");
    }
  };

  // --- Handlers for Monitoring ---
  const handleLoadProduct = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const pid = e.target.value;
    setSelectedProductId(pid);
    if (pid) {
      const analysisFormat = db.getMasterForAnalysis(pid);
      setMasterResult(analysisFormat);
      setAnalysisReport(null); // Clear previous report
      setMonitorSaveStatus('idle');
    } else {
      setMasterResult(null);
    }
  };

  const handleAddRow = () => {
    setInputCounts([...inputCounts, { term: '', count: '' }]);
  };

  const handleRemoveRow = (idx: number) => {
    setInputCounts(inputCounts.filter((_, i) => i !== idx));
  };

  const handleInputChange = (idx: number, field: 'term' | 'count', value: string) => {
    const newRows = [...inputCounts];
    newRows[idx] = { ...newRows[idx], [field]: value };
    setInputCounts(newRows);
  };

  const handleQuickAddTerm = (term: string) => {
    const lastRow = inputCounts[inputCounts.length - 1];
    if (!lastRow.term && !lastRow.count) {
      handleInputChange(inputCounts.length - 1, 'term', term);
    } else {
      setInputCounts([...inputCounts, { term, count: '' }]);
    }
  };

  const runAnalysis = () => {
    if (!masterResult) {
      alert("請先載入產品或產生主檔");
      return;
    }
    const val = parseFloat(exposureVal);

    // VALIDATION ALERT
    if (!exposureVal || isNaN(val) || val <= 0) {
      alert("⚠️ 注意：尚未產生有效的暴露量！\n\n請完整填寫「銷售數量」與「每日使用量」，系統將自動計算分母。");
      return;
    }

    // Filter valid rows: Must have a term name. Count defaults to 0 if empty.
    const validCounts = inputCounts
      .filter(r => r.term.trim() !== '') 
      .map(r => ({
        term: r.term,
        count: parseInt(r.count, 10) || 0
      }));

    // Allow analysis even if validCounts is empty (Report will show 0 cases)
    const report = performAnalysis(masterResult, {
      quarter,
      exposure_value: val,
      exposure_unit: exposureUnit,
      ae_counts: validCounts
    }, {
      includeAllMasterTerms: showAllTerms
    });

    setAnalysisReport(report);
    setMonitorSaveStatus('idle');
  };

  const handleExportCSV = () => {
    if (!analysisReport) return;

    // BOM for Excel to read UTF-8 correctly
    const BOM = "\uFEFF"; 
    const headers = ["判定 (Status)", "AE Term", "SOC", "仿單頻率 (Label Freq)", "本季案例數 (Count)", "發生率 (Rate %)", "仿單門檻 (Threshold %)"];

    const rows = analysisReport.rows.map(row => {
      let statusText = 'Normal';
      if (row.status === 'unexpected') statusText = 'Unexpected';
      if (row.status === 'alert') statusText = 'Alert';
      if (row.status === 'warning') statusText = 'Warning';

      return [
        statusText,
        `"${row.ae_term.replace(/"/g, '""')}"`, // Escape quotes
        `"${row.soc.replace(/"/g, '""')}"`,
        `"${row.frequency_category.replace(/"/g, '""')}"`,
        row.count,
        row.incidence_rate_pct.toFixed(4),
        row.threshold_pct
      ].join(",");
    });

    const csvContent = BOM + headers.join(",") + "\n" + rows.join("\n");
    const blob = new Blob([csvContent], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.setAttribute("download", `PV_Analysis_Report_${quarter}_${new Date().toISOString().slice(0,10)}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);

    // LOG THE EXPORT
    db.addLog('EXPORT', 'MONITOR', `Exported CSV Analysis Report for ${quarter} (Rows: ${analysisReport.rows.length})`);
    setDbUpdateTrigger(prev => prev + 1); // Refresh logs view if active
  };

  const handleSaveAnalysis = () => {
    if (!analysisReport || !selectedProductId) {
      alert("需選擇產品並執行分析後才能儲存");
      return;
    }

    const records: QuarterlyAeMonitor[] = [];
    const now = new Date().toISOString();

    if (analysisReport.rows.length === 0) {
      // HANDLE EMPTY REPORT: Save a single record indicating No AEs
      const id = Date.now().toString(36) + Math.random().toString(36).substring(2);
      records.push({
        id,
        product_id: selectedProductId,
        quarter: quarter,
        exposure_value: parseFloat(exposureVal),
        exposure_unit: exposureUnit,
        ae_term: "本季無不良反應 (No Adverse Events)",
        count: 0,
        rate_pct: 0,
        threshold_pct: 0,
        status: 'normal',
        generated_at: now
      });
    } else {
      // Handle normal report with rows
      analysisReport.rows.forEach(row => {
        let status: 'normal' | 'yellow' | 'red' = 'normal';
        if (row.status === 'alert') status = 'red';
        if (row.status === 'warning') status = 'yellow';
        if (row.status === 'unexpected') status = 'red'; // Unexpected is also a RED flag in DB

        // Simple random ID generation
        const id = Date.now().toString(36) + Math.random().toString(36).substring(2);

        records.push({
          id,
          product_id: selectedProductId,
          quarter: quarter,
          exposure_value: parseFloat(exposureVal),
          exposure_unit: exposureUnit,
          ae_term: row.ae_term,
          count: row.count,
          rate_pct: row.incidence_rate_pct,
          threshold_pct: row.threshold_pct,
          status: status,
          generated_at: now
        });
      });
    }

    if (records.length > 0) {
       db.saveQuarterlyAeMonitors(records);
       setDbUpdateTrigger(prev => prev + 1); // Force library update
    }

    setMonitorSaveStatus('saved');
  };

  const handleDeleteProduct = (pid: string) => {
    if(confirm('確定要刪除此產品及其所有相關資料嗎？此動作將被記錄在稽核日誌中。')) {
      db.deleteProduct(pid);
      setSavedProducts(db.getProducts());
      if (currentExtractionProductId === pid) {
        setCurrentExtractionProductId(null);
      }
      setDbUpdateTrigger(prev => prev + 1);
    }
  };

  // New Handlers for Library Viewing
  const handleViewProduct = (product: Product) => {
    const masters = db.getLabelAeMasters(product.product_id);
    setViewingProduct({ product, masters });
  };

  const handleViewBatch = (batch: MonitorBatch) => {
    const records = db.getMonitorRecordsByBatch(batch.generated_at);
    setViewingBatch({ batch, records });
  };

  const handleDeleteBatch = (batch: MonitorBatch) => {
     if(confirm(`確定要刪除 ${batch.quarter} 的這份監測報告嗎？`)) {
       db.deleteMonitorBatch(batch.generated_at);
       setDbUpdateTrigger(prev => prev + 1);
     }
  };

  return (
    <div 
      className="min-h-screen text-slate-800 font-sans selection:bg-brand-200 selection:text-brand-900"
      style={{
        backgroundColor: '#ffffff',
        backgroundImage: `
          radial-gradient(at 0% 0%, hsla(204,100%,86%,0.4) 0px, transparent 50%),
          radial-gradient(at 50% 0%, hsla(217,100%,90%,0.3) 0px, transparent 50%),
          radial-gradient(at 100% 0%, hsla(186,100%,84%,0.3) 0px, transparent 50%),
          radial-gradient(at 0% 50%, hsla(250,100%,94%,0.3) 0px, transparent 50%),
          radial-gradient(at 100% 50%, hsla(200,100%,88%,0.3) 0px, transparent 50%),
